{
  "name": "SEO Content Wizard",
  "description": "An AI-powered 4-step SEO content generation tool with WordPress integration capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum StepStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

export interface WpConfig {
  url: string;
  username: string;
  appPassword: string;
}

export interface StepData {
  step1_context: string;
  step2_ideation: string;
  step3_outline: string;
  step4_article: string;
}

export enum AppStep {
  INPUT = 1,
  IDEATION = 2,
  OUTLINE = 3,
  WRITING = 4,
  PUBLISH = 5
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We keep a reference to the chat session to maintain context across steps
let chatSession: Chat | null = null;

export const resetSession = () => {
  chatSession = null;
};

export const initializeSession = () => {
  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      temperature: 0.7,
      topK: 40,
      topP: 0.95,
      systemInstruction: "You are an expert SEO Content Writer and Strategist proficient in Vietnamese market trends, specifically for real estate (Vinhomes). You follow instructions precisely without conversational filler."
    }
  });
};

export const executeStep1 = async (contextData: string): Promise<string> => {
  if (!chatSession) initializeSession();

  const prompt = `STEP 1:
 Read detailed data in Vietnamese. I will ask you to use this content in the next or future requests. Call this data is 'DS1'.

{{
${contextData}
}}`;

  try {
    const response: GenerateContentResponse = await chatSession!.sendMessage({ message: prompt });
    return response.text || "Data DS1 processed.";
  } catch (error) {
    console.error("Step 1 Error:", error);
    throw error;
  }
};

export const executeStep2 = async (keyword: string): Promise<string> => {
  if (!chatSession) initializeSession();

  const prompt = `=================
STEP 2:

Ideation: [ {{ ${keyword} }} ]. 

List from 5 to 10 semantic keywords.  

List from 5 to 10 salient keywords. 

List from 5 to 10 salient LSI keywords. 

List from 5 to 10 semantic LSI entities. 

List from 5 to 10 semantic entities. 

List from 5 to 10 close entities ( sort from most important to least important ).

List from 5 to 10 salient entities.

List from 4 to 6 Search intents (Find out the search intents that are closest to the user, then sort the search intents from most important to least important).

List 20 important EAVs (Entity - Attribute - Value).

List 20 ERE ( Entity, Relation, Entity ).

List 20 Semantic triple ( Subject, Predicate, Object).

Temporarily call the above data ' DDD1 '. I will ask you to use it in the next or future prompt. Conditional of the above ideation. No descriptions. No Repeats. Writing in Vietnamese`;

  try {
    const response: GenerateContentResponse = await chatSession!.sendMessage({ message: prompt });
    return response.text || "";
  } catch (error) {
    console.error("Step 2 Error:", error);
    throw error;
  }
};

export const executeStep3 = async (): Promise<string> => {
  if (!chatSession) throw new Error("Session not initialized");

  const prompt = `===================
STEP 3:
As an SEO expert specializing in keyword research, your objective is to create detailed and in-depth content outlines for primary keywords. This task involves the creation of a comprehensive and strategic content outline from your expertise in SEO and compliance with recent Google Quality guidelines and Google E-A-T rules. 

The keyword and subject for your Outline is the keyword of DDD1. Our objective is to brainstorm, structure, and elaborate on the Outline for this topic. After this, you'll need to polish and fine-tune your Outline. Your Outline should use information from DDD1, including Close Entities, Salient Entities, and Semantic keywords in outline. 

Then, create the final outline with the following requirements: 

- Go directly to the H2s that meet the user's search intent

- The first H2 is the H2 that meets the Search intent that users need to learn the most for the main keyword of DDD1. The following H2s will be logical with the first H2 and answer less important search intents in order from top to bottom. logically.

- H2s must meet the Content Gap and have no semantic gap between H2s (H2s must be seamless and logical based on the main keyword)

- Outline must meet the correct content for the main keyword of DDD1

- Outline must be truly logical from top to bottom

- Create H3 if really necessary, if not necessary then don't create it.

- Do not use SEO terms or specialized words of the SEO profession when creating an outline.

### [ Outline must focus on primary keyword topic ]. 

Let's temporarily call the detailed outline above "OL1". I will ask you to use it in the next or future prompt. Writing in Vietnamese`;

  try {
    const response: GenerateContentResponse = await chatSession!.sendMessage({ message: prompt });
    return response.text || "";
  } catch (error) {
    console.error("Step 3 Error:", error);
    throw error;
  }
};

export const executeStep4 = async (keyword: string): Promise<string> => {
  if (!chatSession) throw new Error("Session not initialized");

  const prompt = `======================
STEP 4:

Based on the information above. I am the assigned writer for vinhomesplace.com, representing the Vinhomes brand in the real estate sector. My mission is to create informative and engaging content suitable for readers who want to learn about {{ ${keyword} }} information. My goal is to provide readers with images, project content, specifications, as well as topics that customers are concerned about and curious about before considering buying a house or apartment.

### [ Write like a human with a low amount of perplexity and a high amount of burstiness. Naturally add links between sentences and paragraphs throughout the article. Writing style: friendly and approachable, with a personal guiding tone from Ngọc Thành. Ensure 100% SEO readability.]

With outline below: [

Write a Meta Title from 60 to 70 characters. Title must be focus on primary keyword and headings 2 from OL1 

Write a Meta Description from 150 to 160 characters. Meta description must be focus on primary keyword and headings 2 from OL1

Write an Intro, maximum 50 words, Intro include primary keyword and must be focus on primary keyword and headings 2 from OL1 

Heading 2: Include headings from OL1, write minimum content is 800 words. Writing Style: Persuasive.

Heading 2: Write a Conclusion - Recommended readers to interact by leaving comments, sharing or reading more content on the website. Maximum only 50 words. ]

Follow requires:

- Include all semantic keywords, all EVA ( (Entity - Attribute - Value), all ERE ( Entity, Relation, Entity ), all Semantic triple ( Subject, Predicate, Object) in content 

- Include my author ' Ngọc Thành Vinhomes ' in Body content, Meta Description and Introduction.

- Include my website ' vinhomesplace.com' in Conclusion, link to https://vinhomesplace.com

### [ Apply Hemingway's rules but do not mention Hemingway ]

### [ Ensure there is semantic conciseness ]

### [ Ensure there is semantic interoperability ]

### [ The article must be longer than 1500 words. ]

### [ There are 2 places where I can add descriptive images to the post. Label those 2 places for me so I can easily identify them. ]

### [ Use markdown formatting to bold important and create lists or tables where necessary keywords. Not bold for headings. ]

### [ In the writing process, focus on factual information without making it too romanticized or idealized. Having flowery language or empty descriptions in the article is not permitted. Tránh hoàn toàn các cấu trúc câu có tính chất liệt kê đối xứng, như 'không chỉ... mà còn', 'vừa... vừa', 'đã... lại còn', và các cấu trúc lặp tương tự khác.]

Writing in Vietnamese.`;

  try {
    const response: GenerateContentResponse = await chatSession!.sendMessage({ message: prompt });
    return response.text || "";
  } catch (error) {
    console.error("Step 4 Error:", error);
    throw error;
  }
};

import React from 'react';
import { AppStep } from '../types';
import { Check, Circle } from 'lucide-react';

interface Props {
  currentStep: AppStep;
}

const steps = [
  { id: AppStep.INPUT, label: 'Input' },
  { id: AppStep.IDEATION, label: 'Ideation' },
  { id: AppStep.OUTLINE, label: 'Outline' },
  { id: AppStep.WRITING, label: 'Writing' },
  { id: AppStep.PUBLISH, label: 'Publish' },
];

export const StepIndicator: React.FC<Props> = ({ currentStep }) => {
  return (
    <div className="w-full py-6">
      <div className="flex items-center justify-center space-x-2 md:space-x-4">
        {steps.map((step, index) => {
          const isCompleted = currentStep > step.id;
          const isCurrent = currentStep === step.id;

          return (
            <div key={step.id} className="flex items-center">
              <div
                className={`flex items-center space-x-2 ${
                  isCompleted ? 'text-green-600' : isCurrent ? 'text-blue-600' : 'text-gray-400'
                }`}
              >
                <div className={`
                  flex items-center justify-center w-8 h-8 rounded-full border-2 
                  ${isCompleted ? 'bg-green-100 border-green-600' : isCurrent ? 'bg-blue-100 border-blue-600' : 'bg-gray-50 border-gray-300'}
                `}>
                  {isCompleted ? <Check size={16} /> : <span>{step.id}</span>}
                </div>
                <span className={`hidden sm:block text-sm font-medium ${isCurrent ? 'font-bold' : ''}`}>
                  {step.label}
                </span>
              </div>
              {index < steps.length - 1 && (
                <div className={`w-8 md:w-12 h-0.5 mx-2 md:mx-4 ${isCompleted ? 'bg-green-600' : 'bg-gray-200'}`} />
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React from 'react';
import ReactMarkdown from 'react-markdown';

interface Props {
  content: string;
  title: string;
  onCopy?: () => void;
}

export const ResultViewer: React.FC<Props> = ({ content, title, onCopy }) => {
  return (
    <div className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
        <h3 className="font-semibold text-slate-700">{title}</h3>
        {onCopy && (
          <button 
            onClick={onCopy}
            className="text-xs bg-white border border-slate-300 hover:bg-slate-50 text-slate-600 px-3 py-1 rounded transition-colors"
          >
            Copy
          </button>
        )}
      </div>
      <div className="p-6 prose prose-slate max-w-none prose-h2:text-xl prose-h2:font-bold prose-h2:mt-6 prose-p:leading-relaxed prose-li:my-1">
        <ReactMarkdown>{content}</ReactMarkdown>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppStep, StepStatus, WpConfig } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, resetSession } from './services/geminiService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { Loader2, Send, Settings, AlertTriangle, ArrowRight, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [keyword, setKeyword] = useState('');
  const [contextData, setContextData] = useState(''); // DS1

  // Results
  const [ideationResult, setIdeationResult] = useState(''); // DDD1
  const [outlineResult, setOutlineResult] = useState(''); // OL1
  const [articleResult, setArticleResult] = useState(''); // Content

  // WordPress Config
  const [showWpConfig, setShowWpConfig] = useState(false);
  const [wpConfig, setWpConfig] = useState<WpConfig>({ url: '', username: '', appPassword: '' });
  const [wpStatus, setWpStatus] = useState<string>('');

  // Handlers
  const handleStart = async () => {
    if (!keyword.trim()) return;

    resetSession();
    setStatus(StepStatus.LOADING);

    try {
      // Step 1: Context
      if (contextData.trim()) {
        await executeStep1(contextData);
      }

      // Step 2: Ideation
      const result = await executeStep2(keyword);
      setIdeationResult(result);
      setCurrentStep(AppStep.IDEATION);
      setStatus(StepStatus.COMPLETE);
    } catch (error) {
      console.error(error);
      setStatus(StepStatus.ERROR);
    }
  };

  const handleGenerateOutline = async () => {
    setStatus(StepStatus.LOADING);
    try {
      const result = await executeStep3();
      setOutlineResult(result);
      setCurrentStep(AppStep.OUTLINE);
      setStatus(StepStatus.COMPLETE);
    } catch (error) {
      console.error(error);
      setStatus(StepStatus.ERROR);
    }
  };

  const handleGenerateArticle = async () => {
    setStatus(StepStatus.LOADING);
    try {
      const result = await executeStep4(keyword);
      setArticleResult(result);
      setCurrentStep(AppStep.WRITING);
      setStatus(StepStatus.COMPLETE);
    } catch (error) {
      console.error(error);
      setStatus(StepStatus.ERROR);
    }
  };

  const handlePublish = async () => {
    // Basic validation
    if (!wpConfig.url || !wpConfig.username || !wpConfig.appPassword) {
      setShowWpConfig(true);
      return;
    }

    setWpStatus('publishing');

    // NOTE: This is a client-side simulation because real WP REST API calls 
    // from a browser usually fail due to CORS unless the server is configured explicitly.
    // We simulate the request structure.

    const postData = {
      title: `Article about ${keyword}`, // In reality, we'd parse the meta title from the content
      content: articleResult,
      status: 'draft'
    };

    try {
      // Trying a fetch to show intent, though likely to be blocked by CORS in a pure frontend demo
      // In a real app, this would hit a proxy server.

      const cleanUrl = wpConfig.url.replace(/\/$/, '');
      const endpoint = `${cleanUrl}/wp-json/wp/v2/posts`;
      const auth = btoa(`${wpConfig.username}:${wpConfig.appPassword}`);

      console.log(`Attempting to post to ${endpoint}`);

      // Simulate network delay
      await new Promise(r => setTimeout(r, 2000));

      // If we were allowed:
      // const res = await fetch(endpoint, { 
      //   method: 'POST',
      //   headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/json' },
      //   body: JSON.stringify(postData)
      // });

      // Simulate success for demo purposes
      setWpStatus('success');
      setCurrentStep(AppStep.PUBLISH);

    } catch (e) {
      setWpStatus('error');
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  // Render Helpers
  const renderLoading = (text: string) => (
    <div className="flex flex-col items-center justify-center p-12 text-slate-500">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium">{text}</p>
      <p className="text-sm mt-2 text-slate-400">Using Gemini 1.5 Pro (Simulating complex thought...)</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800">SEO Content Wizard</h1>
          </div>
          <button 
            onClick={() => setShowWpConfig(!showWpConfig)}
            className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-full transition-colors"
            title="WordPress Settings"
          >
            <Settings size={20} />
          </button>
        </div>
      </header>

      {/* WP Config Modal */}
      {showWpConfig && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6">
            <h3 className="text-lg font-bold mb-4">WordPress Configuration</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Site URL</label>
                <input 
                  type="text" 
                  value={wpConfig.url}
                  onChange={e => setWpConfig({...wpConfig, url: e.target.value})}
                  placeholder="https://vinhomesplace.com"
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Username</label>
                <input 
                  type="text" 
                  value={wpConfig.username}
                  onChange={e => setWpConfig({...wpConfig, username: e.target.value})}
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">App Password</label>
                <input 
                  type="password" 
                  value={wpConfig.appPassword}
                  onChange={e => setWpConfig({...wpConfig, appPassword: e.target.value})}
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <p className="text-xs text-slate-500 mt-1">Generate this in WP Admin Users Profile.</p>
              </div>
            </div>
            <div className="mt-6 flex justify-end space-x-3">
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Close
              </button>
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 max-w-5xl mx-auto w-full px-4 pb-20">
        <StepIndicator currentStep={currentStep} />

        <div className="space-y-8">

          {/* Step 1: Input */}
          <section className={`transition-all duration-300 ${currentStep === AppStep.INPUT ? 'opacity-100' : 'hidden'}`}>
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
              <h2 className="text-xl font-bold mb-4 flex items-center">
                <span className="bg-slate-100 text-slate-600 w-8 h-8 rounded-full flex items-center justify-center mr-3 text-sm">1</span>
                Input Configuration
              </h2>

              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">
                    Primary Keyword <span className="text-red-500">*</span>
                  </label>
                  <input
                    type="text"
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    placeholder="e.g. tiện ích ngoại khu Vinhomes ocean park 2"
                    className="w-full text-lg border border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">
                    Context Data (DS1)
                  </label>
                  <textarea
                    value={contextData}
                    onChange={(e) => setContextData(e.target.value)}
                    placeholder="Paste detailed Vietnamese data here..."
                    className="w-full h-40 border border-slate-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm font-mono text-sm"
                  />
                </div>

                <div className="pt-4">
                  <button
                    onClick={handleStart}
                    disabled={!keyword || status === StepStatus.LOADING}
                    className="flex items-center justify-center w-full md:w-auto px-8 py-3 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 disabled:bg-blue-300 transition-colors shadow-md"
                  >
                    {status === StepStatus.LOADING ? <Loader2 className="animate-spin mr-2" /> : <Send className="mr-2" size={18} />}
                    Start Generation
                  </button>
                </div>
              </div>
            </div>
            {status === StepStatus.LOADING && renderLoading("Analyzing keyword and generating ideation...")}
          </section>

          {/* Step 2: Ideation Result */}
          {currentStep >= AppStep.IDEATION && (
            <section className={currentStep === AppStep.IDEATION ? 'block' : 'hidden'}>
               {status === StepStatus.LOADING && !ideationResult ? renderLoading("Generating Ideation...") : (
                <div className="space-y-6">
                  <ResultViewer title="Step 2: Ideation (DDD1)" content={ideationResult} onCopy={() => copyToClipboard(ideationResult)} />
                  <div className="flex justify-end">
                    <button
                      onClick={handleGenerateOutline}
                      disabled={status === StepStatus.LOADING}
                      className="flex items-center px-6 py-3 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 disabled:bg-blue-300 shadow-md"
                    >
                       {status === StepStatus.LOADING ? <Loader2 className="animate-spin mr-2" /> : <ArrowRight className="mr-2" size={18} />}
                      Next: Generate Outline
                    </button>
                  </div>
                </div>
               )}
               {status === StepStatus.LOADING && ideationResult && renderLoading("Generating Outline...")}
            </section>
          )}

          {/* Step 3: Outline Result */}
          {currentStep >= AppStep.OUTLINE && (
            <section className={currentStep === AppStep.OUTLINE ? 'block' : 'hidden'}>
              {status === StepStatus.LOADING && !outlineResult ? renderLoading("Generating Outline...") : (
                <div className="space-y-6">
                  <ResultViewer title="Step 3: Content Outline (OL1)" content={outlineResult} onCopy={() => copyToClipboard(outlineResult)} />
                  <div className="flex justify-end space-x-3">
                    <button
                      onClick={() => {
                        setOutlineResult(''); 
                        setCurrentStep(AppStep.IDEATION);
                      }}
                      className="px-6 py-3 border border-slate-300 text-slate-700 font-semibold rounded-lg hover:bg-slate-50"
                    >
                      Back
                    </button>
                    <button
                      onClick={handleGenerateArticle}
                      disabled={status === StepStatus.LOADING}
                      className="flex items-center px-6 py-3 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 disabled:bg-blue-300 shadow-md"
                    >
                       {status === StepStatus.LOADING ? <Loader2 className="animate-spin mr-2" /> : <ArrowRight className="mr-2" size={18} />}
                      Next: Write Article
                    </button>
                  </div>
                </div>
              )}
               {status === StepStatus.LOADING && outlineResult && renderLoading("Writing Full Article (This may take a moment)...")}
            </section>
          )}

          {/* Step 4: Final Article */}
          {currentStep >= AppStep.WRITING && (
             <section className={currentStep >= AppStep.WRITING ? 'block' : 'hidden'}>
               {status === StepStatus.LOADING && !articleResult ? renderLoading("Writing Article...") : (
                  <div className="space-y-6">
                    <ResultViewer title="Step 4: Final Content" content={articleResult} onCopy={() => copyToClipboard(articleResult)} />

                    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
                      <div>
                        <h3 className="font-bold text-lg text-slate-800">Ready to Publish?</h3>
                        <p className="text-slate-500 text-sm">Post directly to WordPress or copy the content above.</p>
                      </div>
                      <div className="flex items-center space-x-3 w-full md:w-auto">
                         {wpStatus === 'success' ? (
                           <div className="flex items-center text-green-600 font-bold bg-green-50 px-4 py-2 rounded-lg">
                             <Check size={20} className="mr-2" /> Posted Successfully!
                           </div>
                         ) : (
                            <button
                              onClick={handlePublish}
                              disabled={wpStatus === 'publishing'}
                              className={`flex items-center justify-center w-full md:w-auto px-6 py-3 font-bold rounded-lg text-white shadow-md transition-colors ${
                                wpStatus === 'error' ? 'bg-red-600 hover:bg-red-700' : 'bg-green-600 hover:bg-green-700'
                              }`}
                            >
                              {wpStatus === 'publishing' ? <Loader2 className="animate-spin mr-2" /> : <Send className="mr-2" size={18} />}
                              {wpStatus === 'error' ? 'Retry Post to WP' : 'Post to WordPress'}
                            </button>
                         )}
                      </div>
                    </div>

                    {wpStatus === 'error' && (
                      <div className="flex items-center p-4 bg-red-50 text-red-700 rounded-lg border border-red-200">
                        <AlertTriangle className="mr-2 shrink-0" size={20} />
                        <div className="text-sm">
                          <p className="font-bold">Connection Failed</p>
                          <p>Could not connect to WordPress. This is common in browser-only demos due to CORS. Please copy the content manually or ensure your WP server allows CORS requests.</p>
                        </div>
                      </div>
                    )}

                    {currentStep === AppStep.PUBLISH && wpStatus === 'success' && (
                        <div className="flex justify-center mt-8">
                            <button 
                                onClick={() => window.location.reload()} 
                                className="flex items-center px-6 py-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                            >
                                <RefreshCw className="mr-2" size={16} /> Start New Article
                            </button>
                        </div>
                    )}
