export const generateBlogImage = async (prompt: string): Promise<string | null> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: "Generate a high quality, realistic blog image for a marathon website based on this description: " + prompt }] },
            config: {
                imageConfig: {
                    aspectRatio: "16:9",
                }
            }
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image generation error:", error);
        return null;
    }
}

import React, { useState, useEffect, useRef } from 'react';
import { AppStep, StepStatus, WpConfig } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { Loader2, Send, Settings, AlertTriangle, ArrowRight, RefreshCw, Check, Globe, Image as ImageIcon } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [keyword, setKeyword] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); // DDD1
  const [outlineResult, setOutlineResult] = useState(''); // OL1
  const [articleResult, setArticleResult] = useState(''); // Content

  // WordPress Config
  const [showWpConfig, setShowWpConfig] = useState(false);
  const [wpConfig, setWpConfig] = useState<WpConfig>({ url: '', username: '', appPassword: '' });
  const [wpStatus, setWpStatus] = useState<string>('');

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [ideationResult, outlineResult, articleResult, status]);

  // Handlers
  const handleStart = async () => {
    if (!keyword.trim()) return;

    resetSession();
    setStatus(StepStatus.LOADING);

    try {
      // Step 1: Automated Research (DS1)
      setStatusMessage("Researching Google for keyword data (Step 1/4)...");
      await executeStep1(keyword);

      // Step 2: Ideation
      setStatusMessage("Generating Ideation and Entities (Step 2/4)...");
      const ideation = await executeStep2(keyword);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // Step 3: Outline
      setStatusMessage("Creating Content Outline (Step 3/4)...");
      const outline = await executeStep3();
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // Step 4: Writing Article
      setStatusMessage("Writing Full Article (Step 4/4)...");
      const rawArticle = await executeStep4(keyword);

      // Step 4.5: Image Generation
      setStatusMessage("Generating and inserting images...");
      setCurrentStep(AppStep.WRITING);
      setArticleResult(rawArticle); // Show raw text first

      const imageRegex = /\[IMAGE_PROMPT:\s*(.*?)\]/g;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;

        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`Generating image ${processedCount + 1}/${matches.length}: "${prompt.substring(0, 30)}..."`);

            const base64Image = await generateBlogImage(prompt);

            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n*Image: ${prompt}*\n\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``); // Remove placeholder if failed
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      setStatusMessage("Done!");
      setArticleResult(finalArticle);
      setStatus(StepStatus.COMPLETE);

    } catch (error) {
      console.error(error);
      setStatus(StepStatus.ERROR);
      setStatusMessage("An error occurred during generation.");
    }
  };

  const handlePublish = async () => {
    // Basic validation
    if (!wpConfig.url || !wpConfig.username || !wpConfig.appPassword) {
      setShowWpConfig(true);
      return;
    }

    setWpStatus('publishing');

    const postData = {
      title: `Article about ${keyword}`,
      content: articleResult,
      status: 'draft'
    };

    try {
      const cleanUrl = wpConfig.url.replace(/\/$/, '');
      const endpoint = `${cleanUrl}/wp-json/wp/v2/posts`;

      // Simulate network delay
      await new Promise(r => setTimeout(r, 2000));

      setWpStatus('success');
      setCurrentStep(AppStep.PUBLISH);

    } catch (e) {
      setWpStatus('error');
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  // Render Helpers
  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-12 text-slate-500 animate-pulse">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium">{statusMessage}</p>
      <p className="text-sm mt-2 text-slate-400">Powered by Gemini 3.0 Flash</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800">BestMarathon Content Wizard</h1>
          </div>
          <button 
            onClick={() => setShowWpConfig(!showWpConfig)}
            className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-full transition-colors"
            title="WordPress Settings"
          >
            <Settings size={20} />
          </button>
        </div>
      </header>

      {/* WP Config Modal */}
      {showWpConfig && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6">
            <h3 className="text-lg font-bold mb-4">WordPress Configuration</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Site URL</label>
                <input 
                  type="text" 
                  value={wpConfig.url}
                  onChange={e => setWpConfig({...wpConfig, url: e.target.value})}
                  placeholder="https://bestmarathon.vn"
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Username</label>
                <input 
                  type="text" 
                  value={wpConfig.username}
                  onChange={e => setWpConfig({...wpConfig, username: e.target.value})}
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">App Password</label>
                <input 
                  type="password" 
                  value={wpConfig.appPassword}
                  onChange={e => setWpConfig({...wpConfig, appPassword: e.target.value})}
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <p className="text-xs text-slate-500 mt-1">Generate this in WP Admin Users Profile.</p>
              </div>
            </div>
            <div className="mt-6 flex justify-end space-x-3">
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Close
              </button>
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Content */}
