import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We keep a reference to the chat session to maintain context across steps
let chatSession: Chat | null = null;

export const resetSession = () => {
  chatSession = null;
};

export const initializeSession = () => {
  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      temperature: 0.7,
      topK: 40,
      topP: 0.95,
      systemInstruction: "You are an expert SEO Content Writer and Strategist proficient in Vietnamese market trends, specifically for Marathon running, athletics, sports records, running clubs, and the running ecosystem in Vietnam and globally. You follow instructions precisely without conversational filler.",
      tools: [{ googleSearch: {} }]
    }
  });
};

const appendSources = (text: string, response: GenerateContentResponse) => {
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (!chunks || chunks.length === 0) return text;

  let sourcesMd = "\n\n### Sources Referenced\n";
  chunks.forEach((chunk: any) => {
    if (chunk.web) {
      sourcesMd += `- [${chunk.web.title || 'Source'}](${chunk.web.uri})\n`;
    }
  });
  return text + sourcesMd;
};

export const executeStep1 = async (keyword: string): Promise<string> => {
  if (!chatSession) initializeSession();

  const prompt = `STEP 1:
Collect keyword information from multiple different sources to gather data about: "${keyword}".
Read at least 20–30 articles published on Google and other platforms to obtain the most accurate information possible.
Refer to this information set as “DS1”.
Output the gathered information in Vietnamese.`;

  try {
    const response: GenerateContentResponse = await chatSession!.sendMessage({ message: prompt });
    const text = response.text || "Data DS1 processed.";
    return appendSources(text, response);
  } catch (error) {
    console.error("Step 1 Error:", error);
    throw error;
  }
};

