export const generateBlogImage = async (prompt: string): Promise<string | null> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: "Generate a realistic, high-quality photograph style image for a professional marathon blog. Prompt: " + prompt }] },
            config: {
                imageConfig: {
                    aspectRatio: "16:9",
                }
            }
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image generation error:", error);
        return null;
    }
}

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { Copy, Code, FileText, ChevronDown, ChevronUp, Download, Check } from 'lucide-react';

interface Props {
  content: string;
  title: string;
  isCollapsible?: boolean;
  defaultOpen?: boolean;
}

export const ResultViewer: React.FC<Props> = ({ 
  content, 
  title, 
  isCollapsible = false, 
  defaultOpen = true 
}) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const [viewMode, setViewMode] = useState<'preview' | 'raw'>('preview');
  const [copied, setCopied] = useState<'md' | 'html' | null>(null);

  // Update open state if defaultOpen changes (e.g. from parent automation)
  useEffect(() => {
    setIsOpen(defaultOpen);
  }, [defaultOpen]);

  const handleCopy = (type: 'md' | 'html') => {
    if (type === 'md') {
      navigator.clipboard.writeText(content);
    } else {
      // Simple conversion for clipboard (rendering via a temporary element is safer for pure text)
      // For this user, we will try to copy the innerHTML of the preview div if available,
      // or a basic wrap.
      const previewElement = document.getElementById(`preview-${title.replace(/\s/g, '-')}`);
      if (previewElement) {
        navigator.clipboard.writeText(previewElement.innerHTML);
      }
    }
    setCopied(type);
    setTimeout(() => setCopied(null), 2000);
  };

  const handleDownloadImage = (base64Data: string, altText: string) => {
    const link = document.createElement('a');
    link.href = base64Data;
    link.download = `${altText.replace(/\s+/g, '-').slice(0, 30)}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden transition-all duration-300">
      {/* Header */}
      <div 
        className={`bg-slate-50 px-6 py-4 flex justify-between items-center cursor-pointer hover:bg-slate-100 transition-colors ${!isOpen && 'rounded-b-xl'}`}
        onClick={() => isCollapsible && setIsOpen(!isOpen)}
      >
        <div className="flex items-center space-x-3">
          {isCollapsible && (
            <div className="text-slate-400">
              {isOpen ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </div>
          )}
          <h3 className="font-bold text-slate-800 text-lg">{title}</h3>
        </div>

        {isOpen && (
          <div className="flex items-center space-x-2" onClick={e => e.stopPropagation()}>
            <div className="flex bg-slate-200 rounded-lg p-1 mr-4">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  viewMode === 'preview' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Preview
              </button>
              <button
                onClick={() => setViewMode('raw')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  viewMode === 'raw' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Markdown
              </button>
            </div>

            <button 
              onClick={() => handleCopy('md')}
              className="flex items-center space-x-1 text-xs bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-3 py-2 rounded-lg transition-colors font-medium"
              title="Copy Markdown"
            >
              {copied === 'md' ? <Check size={14} className="text-green-600" /> : <FileText size={14} />}
              <span>{copied === 'md' ? 'Copied' : 'Copy MD'}</span>
            </button>

            <button 
              onClick={() => handleCopy('html')}
              className="flex items-center space-x-1 text-xs bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-3 py-2 rounded-lg transition-colors font-medium"
              title="Copy HTML Code"
            >
              {copied === 'html' ? <Check size={14} className="text-green-600" /> : <Code size={14} />}
              <span>{copied === 'html' ? 'Copied' : 'Copy HTML'}</span>
            </button>
          </div>
        )}
      </div>

      {/* Content */}
      {isOpen && (
        <div className="p-8 border-t border-slate-200 bg-white">
          {viewMode === 'preview' ? (
            <div 
              id={`preview-${title.replace(/\s/g, '-')}`} 
              className="prose prose-slate max-w-none prose-headings:font-bold prose-h1:text-3xl prose-h2:text-2xl prose-h2:text-blue-800 prose-h2:mt-8 prose-h2:mb-4 prose-p:leading-relaxed prose-img:rounded-xl prose-img:shadow-lg"
            >
              <ReactMarkdown
                urlTransform={(url) => url} // Allow data: images
                components={{
                  img: ({node, ...props}) => {
                    const isBase64 = props.src?.startsWith('data:');
                    return (
                      <div className="my-8 group relative inline-block w-full">
                        <img 
                          {...props} 
                          className="w-full h-auto rounded-xl shadow-lg border border-slate-100" 
                          alt={props.alt || "Generated Image"}
                        />
                        {isBase64 && (
                          <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                handleDownloadImage(props.src!, props.alt || 'image');
                              }}
                              className="bg-white/90 hover:bg-white text-slate-800 p-2 rounded-full shadow-lg backdrop-blur-sm flex items-center space-x-2 px-4 font-medium text-sm"
                            >
                              <Download size={16} />
                              <span>Download</span>
                            </button>
                          </div>
                        )}
                        <div className="mt-2 text-center text-sm text-slate-500 italic">
                          {props.alt}
                        </div>
                      </div>
                    );
                  }
                }}
              >
                {content}
              </ReactMarkdown>
            </div>
          ) : (
            <textarea
              readOnly
              className="w-full h-[500px] p-4 font-mono text-sm text-slate-700 bg-slate-50 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={content}
            />
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AppStep, StepStatus, WpConfig } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { Loader2, Send, Settings, AlertTriangle, ArrowRight, RefreshCw, Check, Globe, Image as ImageIcon } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [keyword, setKeyword] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); // DDD1
  const [outlineResult, setOutlineResult] = useState(''); // OL1
  const [articleResult, setArticleResult] = useState(''); // Content

  // WordPress Config
  const [showWpConfig, setShowWpConfig] = useState(false);
  const [wpConfig, setWpConfig] = useState<WpConfig>({ url: '', username: '', appPassword: '' });
  const [wpStatus, setWpStatus] = useState<string>('');

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [ideationResult, outlineResult, articleResult, status]);

  // Handlers
  const handleStart = async () => {
    if (!keyword.trim()) return;

    resetSession();
    setStatus(StepStatus.LOADING);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');

    try {
      // Step 1: Automated Research (DS1)
      setStatusMessage("Researching Google for keyword data (Step 1/4)...");
      await executeStep1(keyword);

      // Step 2: Ideation
      setStatusMessage("Generating Ideation and Entities (Step 2/4)...");
      const ideation = await executeStep2(keyword);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // Step 3: Outline
      setStatusMessage("Creating Content Outline (Step 3/4)...");
      const outline = await executeStep3();
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // Step 4: Writing Article
      setStatusMessage("Writing Full Article (Step 4/4)...");
      const rawArticle = await executeStep4(keyword);

      // Step 4.5: Image Generation
      setStatusMessage("Analyzing content and generating visuals...");
      setCurrentStep(AppStep.WRITING);
      setArticleResult(rawArticle); // Show raw text first

      const imageRegex = /\[IMAGE_PROMPT:\s*(.*?)\]/g;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;

        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`Generating image ${processedCount + 1}/${matches.length}: "${prompt.substring(0, 30)}..."`);

            const base64Image = await generateBlogImage(prompt);

            if (base64Image) {
                // We use standard markdown image syntax. The ResultViewer handles the rendering.
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``); // Remove placeholder if failed
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      setStatusMessage("Done!");
      setArticleResult(finalArticle);
      setStatus(StepStatus.COMPLETE);
      setCurrentStep(AppStep.PUBLISH); // Mark as ready to publish

    } catch (error) {
      console.error(error);
      setStatus(StepStatus.ERROR);
      setStatusMessage("An error occurred during generation.");
    }
  };

  const handlePublish = async () => {
    // Basic validation
    if (!wpConfig.url || !wpConfig.username || !wpConfig.appPassword) {
      setShowWpConfig(true);
      return;
    }

    setWpStatus('publishing');

    const postData = {
      title: `Article about ${keyword}`,
      content: articleResult,
      status: 'draft'
    };

    try {
      const cleanUrl = wpConfig.url.replace(/\/$/, '');
      const endpoint = `${cleanUrl}/wp-json/wp/v2/posts`;

      // Simulate network delay
      await new Promise(r => setTimeout(r, 2000));

      setWpStatus('success');
      setCurrentStep(AppStep.PUBLISH);

    } catch (e) {
      setWpStatus('error');
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-12 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium">{statusMessage}</p>
      <p className="text-sm mt-2 text-slate-400">Powered by Gemini 3.0 Flash</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center text-white font-bold shadow-md">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">BestMarathon Wizard</h1>
          </div>
          <button 
            onClick={() => setShowWpConfig(!showWpConfig)}
            className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-full transition-colors"
            title="WordPress Settings"
          >
            <Settings size={20} />
          </button>
