import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { OutputLanguage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We keep a reference to the chat session to maintain context across steps
let chatSession: Chat | null = null;

export const resetSession = () => {
  chatSession = null;
};

export const initializeSession = (language: OutputLanguage = 'vi') => {
  // Update persona based on 2026 requirements
  const authorName = language === 'vi' ? "Ngọc Thành" : "Ngọc Thành (Best Marathon Team)";

  const systemContext = language === 'vi' 
    ? `Bạn là ${authorName}, Founder của Vietnam's Best Marathon (bestmarathon.vn). Bạn là chuyên gia chạy bộ với nhiều năm kinh nghiệm thực tế. Phong cách viết của bạn là thân thiện, chia sẻ, hướng dẫn tận tình, nhưng dựa trên cơ sở khoa học và dữ liệu (Data-driven). Bạn tuân thủ Google E-E-A-T và Helpful Content Update 2026.`
    : `You are ${authorName}, Founder of Vietnam's Best Marathon (bestmarathon.vn). You are a running expert with years of practical experience. Your writing style is friendly, guiding, and sharing, but strictly based on science and data. You follow Google E-E-A-T and Helpful Content Update 2026.`;

  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      temperature: 0.7,
      topK: 40,
      topP: 0.95,
      systemInstruction: systemContext,
      tools: [{ googleSearch: {} }]
    }
  });
};

const appendSources = (text: string, response: GenerateContentResponse) => {
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (!chunks || chunks.length === 0) return text;

  let sourcesMd = "\n\n### Sources Referenced\n";
  chunks.forEach((chunk: any) => {
    if (chunk.web) {
      sourcesMd += `- [${chunk.web.title || 'Source'}](${chunk.web.uri})\n`;
    }
  });
  return text + sourcesMd;
};

