// We keep a reference to the chat session to maintain context across steps
let chatSession: Chat | null = null;

export const resetSession = () => {
  chatSession = null;
};

export const initializeSession = (language: OutputLanguage = 'vi') => {
  // We keep the system instruction minimal now, as the Step 4 prompt is very specific about context.
  const systemContext = language === 'vi' 
    ? `Bạn là trợ lý AI chuyên nghiệp về SEO và Content Marketing. Nhiệm vụ của bạn là thực hiện các bước nghiên cứu và viết bài theo yêu cầu chi tiết.`
    : `You are a professional AI assistant specializing in SEO and Content Marketing. Your task is to execute research and writing steps according to detailed requests.`;

  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      temperature: 0.7,
      topK: 40,
      topP: 0.95,
      systemInstruction: systemContext,
      tools: [{ googleSearch: {} }]
    }
  });
};

const appendSources = (text: string, response: GenerateContentResponse) => {
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (!chunks || chunks.length === 0) return text;

  let sourcesMd = "\n\n### Nguồn tham khảo (Sources)\n";
  chunks.forEach((chunk: any) => {
    if (chunk.web) {
      sourcesMd += `- [${chunk.web.title || 'Source'}](${chunk.web.uri})\n`;
    }
  });
  return text + sourcesMd;
};

