              {/* Step 4: Final Article */}
              {articleResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-200">
                    <ResultViewer 
                      title={`Step 4: Writing (${currentKeyword})`} 
                      content={articleResult} 
                      isCollapsible={true}
                      defaultOpen={true}
                    />
                </section>
              )}
            </>
          )}

          <div ref={bottomRef} />

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Copy, Code, FileText, ChevronDown, ChevronUp, Download, Check, RefreshCw, Loader2 } from 'lucide-react';

interface Props {
  content: string;
  title: string;
  isCollapsible?: boolean;
  defaultOpen?: boolean;
  onRegenerateImage?: (src: string, alt: string) => Promise<void>;
}

export const ResultViewer: React.FC<Props> = ({ 
  content, 
  title, 
  isCollapsible = false, 
  defaultOpen = true,
  onRegenerateImage
}) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const [viewMode, setViewMode] = useState<'preview' | 'raw'>('preview');
  const [copied, setCopied] = useState<'md' | 'html' | null>(null);

  // Track which image is currently regenerating to show spinner
  const [regeneratingImg, setRegeneratingImg] = useState<string | null>(null);

  useEffect(() => {
    setIsOpen(defaultOpen);
  }, [defaultOpen]);

  const handleCopy = (type: 'md' | 'html') => {
    if (type === 'md') {
      navigator.clipboard.writeText(content);
    } else {
      const previewElement = document.getElementById(`preview-${title.replace(/\s/g, '-')}`);
      if (previewElement) {
        navigator.clipboard.writeText(previewElement.innerHTML);
      }
    }
    setCopied(type);
    setTimeout(() => setCopied(null), 2000);
  };

  const handleDownloadImage = (base64Data: string, altText: string) => {
    const link = document.createElement('a');
    link.href = base64Data;
    link.download = `${altText.replace(/\s+/g, '-').slice(0, 30)}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRegenerateClick = async (src: string, alt: string) => {
    if (!onRegenerateImage) return;
    setRegeneratingImg(src);
    try {
        await onRegenerateImage(src, alt);
    } finally {
        setRegeneratingImg(null);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-md border border-slate-200 overflow-hidden transition-all duration-300">
      {/* Header */}
      <div 
        className={`bg-slate-50 px-6 py-4 flex justify-between items-center cursor-pointer hover:bg-slate-100 transition-colors ${!isOpen && 'rounded-b-xl'}`}
        onClick={() => isCollapsible && setIsOpen(!isOpen)}
      >
        <div className="flex items-center space-x-3">
          {isCollapsible && (
            <div className="text-slate-400">
              {isOpen ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </div>
          )}
          <h3 className="font-bold text-slate-800 text-lg">{title}</h3>
        </div>

        {isOpen && (
          <div className="flex items-center space-x-2" onClick={e => e.stopPropagation()}>
            <div className="flex bg-slate-200 rounded-lg p-1 mr-4">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  viewMode === 'preview' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Preview
              </button>
              <button
                onClick={() => setViewMode('raw')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  viewMode === 'raw' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Markdown
              </button>
            </div>

            <button 
              onClick={() => handleCopy('md')}
              className="flex items-center space-x-1 text-xs bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-3 py-2 rounded-lg transition-colors font-medium"
              title="Copy Markdown"
            >
              {copied === 'md' ? <Check size={14} className="text-green-600" /> : <FileText size={14} />}
              <span>{copied === 'md' ? 'Copied' : 'Copy MD'}</span>
            </button>

            <button 
              onClick={() => handleCopy('html')}
              className="flex items-center space-x-1 text-xs bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-3 py-2 rounded-lg transition-colors font-medium"
              title="Copy HTML Code"
            >
              {copied === 'html' ? <Check size={14} className="text-green-600" /> : <Code size={14} />}
              <span>{copied === 'html' ? 'Copied' : 'Copy HTML'}</span>
            </button>
          </div>
        )}
      </div>

      {/* Content */}
      {isOpen && (
        <div className="p-8 border-t border-slate-200 bg-white">
          {viewMode === 'preview' ? (
            <div 
              id={`preview-${title.replace(/\s/g, '-')}`} 
              className="prose prose-slate prose-lg max-w-none 
                prose-headings:font-bold prose-headings:text-slate-800
                prose-h1:text-3xl prose-h1:mb-6 prose-h1:text-blue-800
                prose-h2:text-2xl prose-h2:mt-10 prose-h2:mb-4 prose-h2:text-blue-700 prose-h2:border-b prose-h2:border-blue-100 prose-h2:pb-2
                prose-h3:text-xl prose-h3:mt-6 prose-h3:mb-3 prose-h3:text-indigo-700
                prose-p:leading-7 prose-p:text-slate-700 prose-p:mb-4
                prose-blockquote:border-l-4 prose-blockquote:border-blue-500 prose-blockquote:bg-blue-50 prose-blockquote:py-2 prose-blockquote:px-4 prose-blockquote:italic prose-blockquote:rounded-r-lg prose-blockquote:text-slate-700
                prose-ul:list-disc prose-ul:pl-6 prose-li:mb-2
                prose-img:rounded-xl prose-img:shadow-lg prose-img:mx-auto prose-img:border prose-img:border-slate-100
                prose-strong:text-slate-900 prose-strong:font-bold
                prose-a:text-blue-600 prose-a:no-underline hover:prose-a:underline
                /* Table Styling */
                prose-table:border-collapse prose-table:w-full prose-table:my-8 prose-table:shadow-sm prose-table:rounded-lg prose-table:overflow-hidden
                prose-thead:bg-slate-100
                prose-th:p-4 prose-th:text-left prose-th:font-bold prose-th:text-slate-700 prose-th:border prose-th:border-slate-300
                prose-td:p-4 prose-td:border prose-td:border-slate-300 prose-td:text-slate-600
                prose-tr:even:bg-slate-50
              "
            >
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                urlTransform={(url) => url} // Allow data: images
                components={{
                  img: ({node, ...props}) => {
                    const src = props.src;
                    const isBase64 = typeof src === 'string' && src.startsWith('data:');
                    const isRegenerating = regeneratingImg === src;

                    return (
                      <div className="my-10 group relative inline-block w-full">
                        <figure>
                            {isRegenerating && (
                                <div className="absolute inset-0 bg-white/80 z-10 flex items-center justify-center rounded-xl backdrop-blur-sm">
                                    <div className="flex flex-col items-center">
                                        <Loader2 className="animate-spin text-blue-600 mb-2" size={32} />
                                        <span className="text-sm font-semibold text-blue-600">Regenerating...</span>
                                    </div>
                                </div>
                            )}
                          <img 
                            {...props} 
                            src={typeof src === 'string' ? src : undefined}
                            className="w-full max-h-[600px] object-cover rounded-xl shadow-lg border border-slate-100" 
                            alt={props.alt || "Generated Image"}
                          />
                          {props.alt && (
                            <figcaption className="mt-3 text-center text-sm text-slate-500 italic font-medium bg-slate-50 inline-block px-4 py-1 rounded-full mx-auto w-full">
                              {props.alt}
                            </figcaption>
                          )}
                        </figure>

                        {isBase64 && !isRegenerating && onRegenerateImage && (
                          <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity flex space-x-2">
                             {/* Regenerate Button */}
                             <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                if (typeof src === 'string') {
                                  handleRegenerateClick(src, props.alt || '');
                                }
                              }}
                              className="bg-white/90 hover:bg-blue-50 text-slate-800 p-2 rounded-full shadow-lg backdrop-blur-sm flex items-center space-x-2 px-4 font-medium text-sm transition-transform hover:scale-105 border border-slate-200"
                              title="Tạo lại ảnh khác"
                            >
                              <RefreshCw size={16} className="text-blue-600" />
                              <span>Regenerate</span>
                            </button>

                            {/* Download Button */}
                            <button 
                              onClick={(e) => {
                                e.stopPropagation();
                                if (typeof src === 'string') {
                                  handleDownloadImage(src, props.alt || 'image');
                                }
                              }}
                              className="bg-white/90 hover:bg-white text-slate-800 p-2 rounded-full shadow-lg backdrop-blur-sm flex items-center space-x-2 px-4 font-medium text-sm transition-transform hover:scale-105 border border-slate-200"
                            >
                              <Download size={16} />
                              <span>Download</span>
                            </button>
                          </div>
                        )}
                      </div>
                    );
                  },
                  // Style code blocks (often used for Schema)
                  code({node, inline, className, children, ...props}: any) {
                    const match = /language-(\w+)/.exec(className || '')
                    return !inline && match ? (
                      <div className="relative my-6 rounded-lg overflow-hidden bg-slate-800 shadow-md">
                         <div className="px-4 py-1 bg-slate-700 text-xs text-slate-300 font-mono border-b border-slate-600 flex justify-between">
                            <span>{match[1]}</span>
                         </div>
                         <pre className="p-4 overflow-x-auto text-sm text-slate-100 font-mono">
                           <code className={className} {...props}>
                             {children}
                           </code>
                         </pre>
                      </div>
                    ) : (
                      <code className="bg-slate-100 text-pink-600 px-1 py-0.5 rounded font-mono text-sm" {...props}>
                        {children}
                      </code>
                    )
                  }
                }}
              >
                {content}
              </ReactMarkdown>
            </div>
          ) : (
            <textarea
              readOnly
              className="w-full h-[500px] p-4 font-mono text-sm text-slate-700 bg-slate-50 rounded-lg border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
              value={content}
            />
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AppStep, StepStatus, WpConfig, HistoryItem, OutputLanguage } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { getHistory, saveHistoryItem, deleteHistoryItem } from './services/storageService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { HistorySidebar } from './components/HistorySidebar';
import { Loader2, Send, Settings, AlertTriangle, ArrowRight, RefreshCw, Check, Globe, History, List, X, Languages, UploadCloud } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [bulkInput, setBulkInput] = useState(''); // Textarea input
  const [language, setLanguage] = useState<OutputLanguage>('vi'); // Language selection

  const [queue, setQueue] = useState<string[]>([]); // Processing queue
  const [completedCount, setCompletedCount] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [currentKeyword, setCurrentKeyword] = useState(''); // Currently processing keyword

  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); 
  const [outlineResult, setOutlineResult] = useState(''); 
  const [articleResult, setArticleResult] = useState(''); 

  // History & Logs
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<HistoryItem | null>(null);

  // WordPress Config
  const [showWpConfig, setShowWpConfig] = useState(false);
  const [wpConfig, setWpConfig] = useState<WpConfig>({ url: '', username: '', appPassword: '' });
  const [wpStatus, setWpStatus] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>(''); // Detailed error log for user

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  // Load History on Mount
  useEffect(() => {
    const loadData = async () => {
        const loadedHistory = await getHistory();
        setHistory(loadedHistory);
    };
    loadData();
  }, []);

  useEffect(() => {
    if (status !== StepStatus.IDLE && bottomRef.current) {
      // Small timeout to allow render
      setTimeout(() => {
          bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  }, [ideationResult, outlineResult, articleResult, status, statusMessage]);

  // --- Bulk Processing Logic ---

  const handleStartBulk = async () => {
    const keywords = bulkInput
      .split('\n')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    if (keywords.length === 0) return;

    setQueue(keywords);
    setTotalCount(keywords.length);
    setCompletedCount(0);
    setStatus(StepStatus.LOADING);

    // Start processing the first keyword, capture current language
    processNextKeyword(keywords, language);
  };

  const processNextKeyword = async (remainingQueue: string[], selectedLang: OutputLanguage) => {
    if (remainingQueue.length === 0) {
      setStatus(StepStatus.COMPLETE);
      setStatusMessage("All keywords processed successfully!");
      setCurrentKeyword('');
      return;
    }

    const keyword = remainingQueue[0];
    const nextQueue = remainingQueue.slice(1);

    setCurrentKeyword(keyword);
    setQueue(nextQueue);
    setCompletedCount(prev => totalCount - remainingQueue.length);

    // Reset UI for new keyword
    setCurrentStep(AppStep.INPUT);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');
    resetSession();

    try {
      const langLabel = selectedLang === 'vi' ? 'VI' : 'EN';

      // --- Step 1 ---
      setStatusMessage(`[${keyword}][${langLabel}] Researching data (Step 1/4)...`);
      await executeStep1(keyword, selectedLang);

      // --- Step 2 ---
      setStatusMessage(`[${keyword}][${langLabel}] Generating Ideation (Step 2/4)...`);
      const ideation = await executeStep2(keyword, selectedLang);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // --- Step 3 ---
      setStatusMessage(`[${keyword}][${langLabel}] Creating Outline (Step 3/4)...`);
      const outline = await executeStep3(selectedLang);
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // --- Step 4 ---
      setStatusMessage(`[${keyword}][${langLabel}] Writing Article (Step 4/4)...`);
      const rawArticle = await executeStep4(keyword, selectedLang);
      setArticleResult(rawArticle);
      setCurrentStep(AppStep.WRITING);

      // --- Images ---
      setStatusMessage(`[${keyword}] Generating Images (Vietnamese Context)...`);
      // Updated Regex to support [HÌNH ẢNH: ...] based on new prompt
      const imageRegex = /\[(?:IMAGE_PROMPT|HÌNH ẢNH):\s*(.*?)\]/gi;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;
        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`[${keyword}] Image ${processedCount + 1}/${matches.length}...`);
            const base64Image = await generateBlogImage(prompt);
            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``);
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      // --- Save to History ---
      const newItem: HistoryItem = {
        id: "", // Service will assign unique ID
        keyword: keyword,
        content: finalArticle,
        timestamp: Date.now(),
        language: selectedLang
      };

      console.log("Saving article to DB...");
      const updatedHistory = await saveHistoryItem(newItem);
      setHistory(updatedHistory);

      // --- Trigger Next ---
      setCompletedCount(prev => prev + 1);

      // Small delay between articles to avoid rate limits abruptly
      setStatusMessage(`[${keyword}] Finished! Starting next in 3s...`);
      await new Promise(r => setTimeout(r, 3000));

      processNextKeyword(nextQueue, selectedLang);

    } catch (error) {
      console.error(error);
      const errorItem: HistoryItem = {
        id: "",
        keyword: keyword + " (FAILED)",
        content: `Error processing: ${error}`,
        timestamp: Date.now(),
        language: selectedLang
      };
      const updatedHistory = await saveHistoryItem(errorItem);
      setHistory(updatedHistory);

      setStatusMessage(`Error with "${keyword}". Moving to next...`);
      await new Promise(r => setTimeout(r, 2000));
      processNextKeyword(nextQueue, selectedLang);
    }
  };

  // --- REGENERATE IMAGE LOGIC ---
  const handleRegenerateImage = async (oldSrc: string, altText: string) => {
      // Find the current content (either live or viewing history)
      const currentContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;

      // Generate new image
      const newBase64 = await generateBlogImage(altText);

      if (newBase64) {
          // Replace in content string
          // Note: We need to be careful about replacing strings. 
          // The Markdown image format is: ![altText](data:...)
          // We will look for the specific data string to replace.
          const newContent = currentContent.replace(oldSrc, newBase64);

          if (viewingHistoryItem) {
              const updatedItem = { ...viewingHistoryItem, content: newContent };
              setViewingHistoryItem(updatedItem);
              const updatedHistory = await saveHistoryItem(updatedItem);
              setHistory(updatedHistory);
          } else {
              setArticleResult(newContent);
              // Also update the latest history item if it exists and matches current keyword
              const existingItem = history.find(h => h.keyword === currentKeyword);
              if (existingItem) {
                  const updatedItem = { ...existingItem, content: newContent };
                  const updatedHistory = await saveHistoryItem(updatedItem);
                  setHistory(updatedHistory);
              }
          }
      } else {
          alert("Could not regenerate image. Please try again.");
      }
  };

  // History Handlers
  const handleDeleteHistory = async (id: string) => {
    const updated = await deleteHistoryItem(id);
    setHistory(updated);
    if (viewingHistoryItem?.id === id) setViewingHistoryItem(null);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setViewingHistoryItem(item);
    setErrorMessage(''); // Clear error when switching items
    setWpStatus('');
    setShowHistory(false);
  };

  // --- WORDPRESS PUBLISHING LOGIC ---

  const parseMetaData = (fullContent: string) => {
      const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
      const match = fullContent.match(metaBlockRegex);

      let title = "";
      let description = "";
      let slug = "";
      let cleanContent = fullContent;

      if (match) {
          const metaBlock = match[1];
          title = metaBlock.match(/Meta Title:\s*(.*)/)?.[1]?.trim() || "";
          description = metaBlock.match(/Meta Description:\s*(.*)/)?.[1]?.trim() || "";
          slug = metaBlock.match(/Slug:\s*(.*)/)?.[1]?.trim() || "";

          // Remove the meta block from the content to be published
          cleanContent = fullContent.replace(match[0], "").trim();
      }

      // Also remove the "========== NỘI DUNG BÀI VIẾT ==========" and "========== KẾT THÚC BÀI VIẾT ==========" markers if present
      cleanContent = cleanContent
          .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
          .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
          .trim();

      return { title, description, slug, cleanContent };
  };

  const uploadImageToWP = async (base64Data: string, altText: string, wpConfig: WpConfig) => {
      // 1. Convert Base64 to Blob
      const parts = base64Data.split(',');
      const byteString = atob(parts[1]);
      const mimeString = parts[0].split(':')[1].split(';')[0]; // e.g., image/png

      const ab = new ArrayBuffer(byteString.length);
      const ia = new Uint8Array(ab);
      for (let i = 0; i < byteString.length; i++) {
          ia[i] = byteString.charCodeAt(i);
      }
      const blob = new Blob([ab], { type: mimeString });

      // Determine extension
      let extension = 'png';
      if (mimeString === 'image/jpeg') extension = 'jpg';
      if (mimeString === 'image/webp') extension = 'webp';

      // 2. Prepare FormData
      const formData = new FormData();
      // Filename needs to be clean
      const cleanFileName = altText.replace(/[^a-z0-9]/gi, '-').toLowerCase().slice(0, 50);
      const fileName = `${cleanFileName}-${Date.now()}.${extension}`;

      formData.append('file', blob, fileName);
      formData.append('alt_text', altText);
      formData.append('title', altText); // Important for WP Media Library

      // 3. Upload to WP
      const authHeader = 'Basic ' + btoa(wpConfig.username + ':' + wpConfig.appPassword);
      // Remove trailing slash from URL if present
      const baseUrl = wpConfig.url.replace(/\/$/, '');

      try {
        const response = await fetch(`${baseUrl}/wp-json/wp/v2/media`, {
            method: 'POST',
            headers: {
                'Authorization': authHeader,
                // Do NOT set Content-Type header manually for FormData, browser does it with boundary
            },
            body: formData
        });

        const responseData = await response.json();

        if (!response.ok) {
            // WordPress returns error object: { code: '...', message: '...', data: ... }
            const errorMsg = responseData.message || responseData.code || 'Unknown upload error';
            throw new Error(`Upload Failed: ${errorMsg}`);
        }

        return responseData.source_url; // Success
      } catch (e: any) {
        if (e.message.includes('Failed to fetch')) {
             throw new Error("CORS Error or Network Issue. Check if your WP site supports HTTPS and allows cross-origin requests.");
        }
        throw e;
      }
  };

  const handlePublish = async () => {
    // Publish the current visible article (either from live process or history viewer)
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    const fallbackTitle = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;

    if (!wpConfig.url || !wpConfig.username || !wpConfig.appPassword) {
      setShowWpConfig(true);
      return;
    }

    setWpStatus('publishing');
    setErrorMessage(''); // Reset previous errors

    try {
      // 1. Parse Meta Data and Clean Content
      const { title, description, slug, cleanContent } = parseMetaData(rawContent);
      const finalTitle = title || fallbackTitle;

      let contentToUpload = cleanContent;

      // 2. Find all Base64 images
      const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
      const matches = [...cleanContent.matchAll(imageRegex)];

      if (matches.length > 0) {
          setWpStatus(`uploading_images`);
          // 3. Iterate and upload each image
          for (let i = 0; i < matches.length; i++) {
              const match = matches[i];
              const altText = match[1] || `image-${i}`;
              const base64Data = match[2];

              try {
                  const uploadedUrl = await uploadImageToWP(base64Data, altText, wpConfig);
                  // Replace base64 with new URL in content
                  contentToUpload = contentToUpload.replace(base64Data, uploadedUrl);
              } catch (imgErr: any) {
                  console.error("Failed to upload image:", imgErr);
                  // If image upload fails, we abort the whole process to avoid broken posts
                  // Or we could continue with broken images? Let's throw to warn user.
                  throw new Error(`Image Upload Error: ${imgErr.message}`);
              }
          }
      }

      setWpStatus('publishing_post');

      // 4. Publish Post
      const authHeader = 'Basic ' + btoa(wpConfig.username + ':' + wpConfig.appPassword);
      const baseUrl = wpConfig.url.replace(/\/$/, '');

      const postResponse = await fetch(`${baseUrl}/wp-json/wp/v2/posts`, {
          method: 'POST',
          headers: {
              'Content-Type': 'application/json',
              'Authorization': authHeader
          },
          body: JSON.stringify({
              title: finalTitle,
              content: contentToUpload, 
              slug: slug || undefined,
              excerpt: description || undefined,
              status: 'draft' // Safety first: save as draft
          })
      });

      const postData = await postResponse.json();

      if (!postResponse.ok) {
        const errorMsg = postData.message || postData.code || "Unknown WP Error";
        throw new Error(`Post Creation Failed: ${errorMsg}`);
      }

      setWpStatus('success');
      setTimeout(() => setWpStatus(''), 5000);

    } catch (e: any) {
      console.error(e);
      setWpStatus('error');
      // Extract clean error message
      let msg = e.message;
      if (msg === 'Failed to fetch') {
         msg = "Network Error: Could not connect to WordPress. Possible causes: CORS blocks, mixed content (HTTP vs HTTPS), or invalid URL.";
      }
      setErrorMessage(msg);
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-8 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm mb-8">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium text-slate-800">{statusMessage}</p>
      <div className="w-full max-w-md bg-gray-200 rounded-full h-2.5 mt-4">
        <div 
          className="bg-blue-600 h-2.5 rounded-full transition-all duration-500" 
          style={{ width: `${totalCount > 0 ? (completedCount / totalCount) * 100 : 0}%` }}
        ></div>
      </div>
      <p className="text-xs mt-2 text-slate-500">Processed {completedCount} of {totalCount} keywords</p>
    </div>
  );

  // Reusable Publish Button Component
  const PublishButton = () => (
      <div className="flex flex-col items-end">
         <button 
            onClick={handlePublish}
            disabled={wpStatus === 'publishing' || wpStatus === 'uploading_images' || wpStatus === 'publishing_post'}
            className={`flex items-center space-x-2 ${wpStatus === 'error' ? 'bg-red-600 hover:bg-red-700' : 'bg-green-600 hover:bg-green-700'} text-white px-6 py-3 rounded-lg text-lg font-bold shadow-md hover:shadow-lg transition-all disabled:opacity-50`}
         >
           {wpStatus === 'publishing' && <Loader2 className="animate-spin" size={20} />}
           {wpStatus === 'uploading_images' && <span>Uploading Images...</span>}
           {wpStatus === 'publishing_post' && <span>Creating Post...</span>}
           {wpStatus === 'success' && <span>Published! (Draft)</span>}
           {wpStatus === 'error' && <span>Failed (Retry)</span>}
           {!wpStatus && (
               <>
                 <UploadCloud size={20} className="mr-2" />
                 <span>Publish to WordPress</span>
               </>
           )}
         </button>

         {/* Error Message Display */}
         {wpStatus === 'error' && errorMessage && (
            <div className="mt-3 max-w-lg text-right animate-in fade-in slide-in-from-top-1">
                <div className="inline-flex items-start text-sm text-red-700 font-medium bg-red-50 p-3 rounded-lg border border-red-200 shadow-sm">
                    <AlertTriangle size={16} className="mr-2 mt-0.5 flex-shrink-0" />
                    <span>{errorMessage}</span>
                </div>
            </div>
         )}

         {wpStatus === 'success' && (
             <div className="mt-2 text-green-600 font-medium text-sm animate-in fade-in">
                 Successfully created draft! Check your WP Admin.
             </div>
         )}
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">

      {/* History Sidebar */}
      <HistorySidebar 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        history={history}
        onSelect={handleSelectHistory}
        onDelete={handleDeleteHistory}
      />

      {/* Viewing History Item Modal */}
      {viewingHistoryItem && (
        <div className="fixed inset-0 z-50 bg-slate-100 overflow-y-auto">
          <div className="max-w-5xl mx-auto px-4 py-8">
             <div className="flex items-center justify-between mb-6">
                <button 
                  onClick={() => setViewingHistoryItem(null)}
                  className="flex items-center text-slate-600 hover:text-blue-600 font-bold bg-white px-4 py-2 rounded-lg shadow-sm"
                >
                  <ArrowRight className="rotate-180 mr-2" /> Back to Generator
                </button>
                <div className="flex flex-col items-end">
                   <div className="flex items-center space-x-2 mb-2">
                      <span className="text-xs font-bold text-slate-400 uppercase">{viewingHistoryItem.language || 'vi'}</span>
                      <span className="text-sm text-slate-500">Saved on {new Date(viewingHistoryItem.timestamp).toLocaleDateString()}</span>
                   </div>

                   <PublishButton />
                </div>
             </div>
             <ResultViewer 
               title={`[LOG] ${viewingHistoryItem.keyword}`} 
               content={viewingHistoryItem.content} 
               isCollapsible={false}
               onRegenerateImage={handleRegenerateImage}
             />
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center text-white font-bold shadow-md">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight hidden md:block">BestMarathon Wizard</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowHistory(true)}
              className="flex items-center px-3 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <History size={18} className="mr-2" />
              <span className="font-medium">History ({history.length})</span>
            </button>
            <div className="h-6 w-px bg-slate-200 mx-2"></div>
            <button 
              onClick={() => setShowWpConfig(!showWpConfig)}
              className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 rounded-full transition-colors"
              title="WordPress Settings"
            >
              <Settings size={20} />
            </button>
          </div>
        </div>
      </header>

      {/* WP Config Modal */}
      {showWpConfig && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6">
            <h3 className="text-lg font-bold mb-4">WordPress Configuration</h3>
            <p className="text-sm text-slate-500 mb-4">You need to use "Application Passwords" from your User Profile in WordPress, not your login password.</p>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Site URL</label>
                <input 
                  type="text" 
                  value={wpConfig.url}
                  onChange={e => setWpConfig({...wpConfig, url: e.target.value})}
                  placeholder="https://bestmarathon.vn"
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Username (or Email)</label>
                <input 
                  type="text" 
                  value={wpConfig.username}
                  onChange={e => setWpConfig({...wpConfig, username: e.target.value})}
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Application Password</label>
                <input 
                  type="password" 
                  value={wpConfig.appPassword}
                  onChange={e => setWpConfig({...wpConfig, appPassword: e.target.value})}
                  placeholder="xxxx xxxx xxxx xxxx"
                  className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
            <div className="mt-6 flex justify-end space-x-3">
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Close
              </button>
              <button 
                onClick={() => setShowWpConfig(false)}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className={`flex-1 max-w-5xl mx-auto w-full px-4 pb-20 pt-6 transition-opacity ${viewingHistoryItem ? 'opacity-0 pointer-events-none fixed' : 'opacity-100'}`}>

        {/* Step Indicator only shows when processing */}
        {status !== StepStatus.IDLE && status !== StepStatus.COMPLETE && (
           <StepIndicator currentStep={currentStep} />
        )}

        <div className="space-y-8 mt-6">

          {/* Step 1: Bulk Input - Only show when IDLE */}
          {status === StepStatus.IDLE && (
            <section className="animate-in fade-in zoom-in duration-300">
              <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100">
                <div className="flex items-center justify-between mb-6">
                   <div className="flex items-center">
                     <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-lg mr-4">1</div>
                     <h2 className="text-2xl font-bold text-slate-800">Bulk Keywords</h2>
                   </div>
                </div>

                <div className="space-y-6 ml-14">
                  <div className="flex space-x-4">
                     {/* Text Area */}
                     <div className="flex-1">
                        <textarea
                          value={bulkInput}
                          onChange={(e) => setBulkInput(e.target.value)}
                          placeholder="e.g.&#10;Kỷ lục marathon thế giới&#10;Lịch tập chạy 21km&#10;Dinh dưỡng cho runner..."
                          className="w-full h-40 text-lg border border-slate-300 rounded-xl p-4 focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all shadow-sm font-mono text-slate-700 leading-relaxed"
                        />
                        <p className="text-sm text-slate-500 mt-3 flex items-center">
                          <List size={16} className="mr-2" />
                          Enter multiple keywords (one per line).
                        </p>
                     </div>
                  </div>

                  {/* Language & Actions */}
                  <div className="flex flex-col md:flex-row items-center gap-4 pt-2">
                    <div className="w-full md:w-64">
                       <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
                         <Languages size={16} className="mr-2" /> Output Language
                       </label>
                       <div className="relative">
                         <select
                           value={language}
                           onChange={(e) => setLanguage(e.target.value as OutputLanguage)}
                           className="w-full appearance-none bg-white border border-slate-300 text-slate-700 py-3 px-4 pr-8 rounded-xl leading-tight focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 shadow-sm font-medium"
                         >
                           <option value="vi">Tiếng Việt (Vietnamese)</option>
                           <option value="en">English (Global)</option>
                         </select>
                         <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-500">
                           <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                         </div>
                       </div>
                    </div>

                    <button
                      onClick={handleStartBulk}
                      disabled={!bulkInput.trim()}
                      className="flex-1 w-full md:w-auto mt-6 md:mt-0 flex items-center justify-center px-10 py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-bold text-lg rounded-xl hover:shadow-lg hover:scale-[1.02] active:scale-[0.98] disabled:opacity-70 disabled:hover:scale-100 transition-all"
                    >
                      <Send className="mr-2" size={20} />
                      Start Bulk Automation
                    </button>
                  </div>
                </div>
              </div>
            </section>
          )}

          {/* Global Loader & Progress */}
          {status === StepStatus.LOADING && renderLoading()}

          {/* Completion State */}
          {status === StepStatus.COMPLETE && (
            <div className="bg-green-50 border border-green-200 rounded-xl p-8 text-center animate-in zoom-in duration-300">
               <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                 <Check size={32} />
               </div>
               <h2 className="text-2xl font-bold text-green-800 mb-2">All Tasks Completed!</h2>
               <p className="text-green-700 mb-6">Processed {totalCount} keywords successfully. All articles are saved in History.</p>
               <div className="flex justify-center space-x-4">
                  <button 
                    onClick={() => setShowHistory(true)}
                    className="bg-white border border-green-200 text-green-700 hover:bg-green-100 px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    View History Log
                  </button>
                  <button 
                    onClick={() => {
                       setStatus(StepStatus.IDLE);
                       setBulkInput('');
                       setIdeationResult('');
                       setOutlineResult('');
                       setArticleResult('');
                       setCompletedCount(0);
                       setTotalCount(0);
                    }} 
                    className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    Start New Batch
                  </button>
               </div>
            </div>
          )}

          {/* Current Processing Results - visible in LOADING or COMPLETE state */}
          {(status === StepStatus.LOADING || status === StepStatus.COMPLETE) && (
            <>
              {/* Step 2: Ideation */}
              {ideationResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <ResultViewer 
                      title={`Step 2: Ideation (${currentKeyword})`} 
                      content={ideationResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {/* Step 3: Outline */}
              {outlineResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-100">
                    <ResultViewer 
                      title={`Step 3: Outline (${currentKeyword})`} 
                      content={outlineResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {/* Step 4: Final Article & Publish Button */}
              {articleResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-200 space-y-6">
                    <ResultViewer 
                      title={`Step 4: Writing (${currentKeyword})`} 
                      content={articleResult} 
                      isCollapsible={true}
                      defaultOpen={true}
                      onRegenerateImage={handleRegenerateImage}
                    />

                    {/* Publish Button Block */}
                    <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex items-center justify-between">
                       <div className="flex items-center space-x-3 text-slate-600">
                          <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                             <Settings size={24} />
                          </div>
                          <div>
                            <p className="font-bold text-slate-800">Ready to Publish?</p>
                            <p className="text-sm text-slate-500">Review content and images before sending to WordPress.</p>
                          </div>
                       </div>
                       <PublishButton />
                    </div>
                </section>
              )}
            </>
          )}

          <div ref={bottomRef} />

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppStep, StepStatus, WpConfig, HistoryItem, OutputLanguage } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { getHistory, saveHistoryItem, deleteHistoryItem } from './services/storageService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { HistorySidebar } from './components/HistorySidebar';
import { Loader2, Send, Settings, AlertTriangle, ArrowRight, RefreshCw, Check, Globe, History, List, X, Languages, UploadCloud, Wifi, HelpCircle, Copy } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [bulkInput, setBulkInput] = useState(''); // Textarea input
  const [language, setLanguage] = useState<OutputLanguage>('vi'); // Language selection

  const [queue, setQueue] = useState<string[]>([]); // Processing queue
  const [completedCount, setCompletedCount] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [currentKeyword, setCurrentKeyword] = useState(''); // Currently processing keyword

  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); 
  const [outlineResult, setOutlineResult] = useState(''); 
  const [articleResult, setArticleResult] = useState(''); 

  // History & Logs
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<HistoryItem | null>(null);

  // WordPress Config
  const [showWpConfig, setShowWpConfig] = useState(false);
  const [wpConfig, setWpConfig] = useState<WpConfig>({ url: '', username: '', appPassword: '' });
  const [wpStatus, setWpStatus] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>(''); // Detailed error log for user
  const [showCorsHelp, setShowCorsHelp] = useState(false);
  const [connectionTestResult, setConnectionTestResult] = useState<{success: boolean; msg: string} | null>(null);

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  // Load History on Mount
  useEffect(() => {
    const loadData = async () => {
        const loadedHistory = await getHistory();
        setHistory(loadedHistory);
    };
    loadData();
  }, []);

  useEffect(() => {
    if (status !== StepStatus.IDLE && bottomRef.current) {
      // Small timeout to allow render
      setTimeout(() => {
          bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  }, [ideationResult, outlineResult, articleResult, status, statusMessage]);

  // --- Bulk Processing Logic ---

  const handleStartBulk = async () => {
    const keywords = bulkInput
      .split('\n')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    if (keywords.length === 0) return;

    setQueue(keywords);
    setTotalCount(keywords.length);
    setCompletedCount(0);
    setStatus(StepStatus.LOADING);

    // Start processing the first keyword, capture current language
    processNextKeyword(keywords, language);
  };

  const processNextKeyword = async (remainingQueue: string[], selectedLang: OutputLanguage) => {
    if (remainingQueue.length === 0) {
      setStatus(StepStatus.COMPLETE);
      setStatusMessage("All keywords processed successfully!");
      setCurrentKeyword('');
      return;
    }

    const keyword = remainingQueue[0];
    const nextQueue = remainingQueue.slice(1);

    setCurrentKeyword(keyword);
    setQueue(nextQueue);
    setCompletedCount(prev => totalCount - remainingQueue.length);

    // Reset UI for new keyword
    setCurrentStep(AppStep.INPUT);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');
    resetSession();

    try {
      const langLabel = selectedLang === 'vi' ? 'VI' : 'EN';

      // --- Step 1 ---
      setStatusMessage(`[${keyword}][${langLabel}] Researching data (Step 1/4)...`);
      await executeStep1(keyword, selectedLang);

      // --- Step 2 ---
      setStatusMessage(`[${keyword}][${langLabel}] Generating Ideation (Step 2/4)...`);
      const ideation = await executeStep2(keyword, selectedLang);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // --- Step 3 ---
      setStatusMessage(`[${keyword}][${langLabel}] Creating Outline (Step 3/4)...`);
      const outline = await executeStep3(selectedLang);
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // --- Step 4 ---
      setStatusMessage(`[${keyword}][${langLabel}] Writing Article (Step 4/4)...`);
      const rawArticle = await executeStep4(keyword, selectedLang);
      setArticleResult(rawArticle);
      setCurrentStep(AppStep.WRITING);

      // --- Images ---
      setStatusMessage(`[${keyword}] Generating Images (Vietnamese Context)...`);
      // Updated Regex to support [HÌNH ẢNH: ...] based on new prompt
      const imageRegex = /\[(?:IMAGE_PROMPT|HÌNH ẢNH):\s*(.*?)\]/gi;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;
        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`[${keyword}] Image ${processedCount + 1}/${matches.length}...`);
            const base64Image = await generateBlogImage(prompt);
            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``);
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      // --- Save to History ---
      const newItem: HistoryItem = {
        id: "", // Service will assign unique ID
        keyword: keyword,
        content: finalArticle,
        timestamp: Date.now(),
        language: selectedLang
      };

      console.log("Saving article to DB...");
      const updatedHistory = await saveHistoryItem(newItem);
      setHistory(updatedHistory);

      // --- Trigger Next ---
      setCompletedCount(prev => prev + 1);

      // Small delay between articles to avoid rate limits abruptly
      setStatusMessage(`[${keyword}] Finished! Starting next in 3s...`);
      await new Promise(r => setTimeout(r, 3000));

      processNextKeyword(nextQueue, selectedLang);

    } catch (error) {
      console.error(error);
      const errorItem: HistoryItem = {
        id: "",
        keyword: keyword + " (FAILED)",
        content: `Error processing: ${error}`,
        timestamp: Date.now(),
        language: selectedLang
      };
      const updatedHistory = await saveHistoryItem(errorItem);
      setHistory(updatedHistory);

      setStatusMessage(`Error with "${keyword}". Moving to next...`);
      await new Promise(r => setTimeout(r, 2000));
      processNextKeyword(nextQueue, selectedLang);
    }
  };

  // --- REGENERATE IMAGE LOGIC ---
  const handleRegenerateImage = async (oldSrc: string, altText: string) => {
      // Find the current content (either live or viewing history)
      const currentContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;

      // Generate new image
      const newBase64 = await generateBlogImage(altText);

      if (newBase64) {
          // Replace in content string
          const newContent = currentContent.replace(oldSrc, newBase64);

          if (viewingHistoryItem) {
              const updatedItem = { ...viewingHistoryItem, content: newContent };
              setViewingHistoryItem(updatedItem);
              const updatedHistory = await saveHistoryItem(updatedItem);
              setHistory(updatedHistory);
          } else {
              setArticleResult(newContent);
              const existingItem = history.find(h => h.keyword === currentKeyword);
              if (existingItem) {
                  const updatedItem = { ...existingItem, content: newContent };
                  const updatedHistory = await saveHistoryItem(updatedItem);
                  setHistory(updatedHistory);
              }
          }
      } else {
          alert("Could not regenerate image. Please try again.");
      }
  };

  // History Handlers
  const handleDeleteHistory = async (id: string) => {
    const updated = await deleteHistoryItem(id);
    setHistory(updated);
    if (viewingHistoryItem?.id === id) setViewingHistoryItem(null);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setViewingHistoryItem(item);
    setErrorMessage(''); // Clear error when switching items
    setWpStatus('');
    setShowHistory(false);
  };

  // --- WORDPRESS PUBLISHING LOGIC ---

  const getCleanWpUrl = (url: string) => {
    let clean = url.trim();
    if (!clean) return '';
    // Auto-prepend https:// if missing
    if (!clean.startsWith('http://') && !clean.startsWith('https://')) {
        clean = 'https://' + clean;
    }
    // Remove trailing slash
    return clean.replace(/\/$/, '');
  };

  const parseMetaData = (fullContent: string) => {
      const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
      const match = fullContent.match(metaBlockRegex);

      let title = "";
      let description = "";
      let slug = "";
      let cleanContent = fullContent;

      if (match) {
          const metaBlock = match[1];
          title = metaBlock.match(/Meta Title:\s*(.*)/)?.[1]?.trim() || "";
          description = metaBlock.match(/Meta Description:\s*(.*)/)?.[1]?.trim() || "";
          slug = metaBlock.match(/Slug:\s*(.*)/)?.[1]?.trim() || "";
          cleanContent = fullContent.replace(match[0], "").trim();
      }

      cleanContent = cleanContent
          .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
          .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
          .trim();

      return { title, description, slug, cleanContent };
  };

  const testWpConnection = async () => {
     setConnectionTestResult(null);
     const baseUrl = getCleanWpUrl(wpConfig.url);

     if (!baseUrl || !wpConfig.username || !wpConfig.appPassword) {
         setConnectionTestResult({ success: false, msg: "Please fill all fields." });
         return;
     }

     try {
         const authHeader = 'Basic ' + btoa(wpConfig.username + ':' + wpConfig.appPassword);
         const response = await fetch(`${baseUrl}/wp-json/wp/v2/users/me`, {
             method: 'GET',
             headers: {
                 'Authorization': authHeader,
                 'Content-Type': 'application/json'
             }
         });

         if (response.ok) {
             const data = await response.json();
             setConnectionTestResult({ success: true, msg: `Connected as ${data.name}!` });
         } else {
             if (response.status === 401 || response.status === 403) {
                 setConnectionTestResult({ success: false, msg: "Authentication Failed. Check Username/App Password." });
             } else {
                 setConnectionTestResult({ success: false, msg: `Server Error: ${response.status} ${response.statusText}` });
             }
         }
     } catch (e: any) {
         if (e.message.includes("Failed to fetch")) {
             setConnectionTestResult({ success: false, msg: "CORS/Network Error. Browser blocked the request. See Help." });
         } else {
             setConnectionTestResult({ success: false, msg: e.message });
         }
     }
  };

  const uploadImageToWP = async (base64Data: string, altText: string, wpConfig: WpConfig) => {
      const parts = base64Data.split(',');
      const byteString = atob(parts[1]);
      const mimeString = parts[0].split(':')[1].split(';')[0];

      const ab = new ArrayBuffer(byteString.length);
      const ia = new Uint8Array(ab);
      for (let i = 0; i < byteString.length; i++) {
          ia[i] = byteString.charCodeAt(i);
      }
      const blob = new Blob([ab], { type: mimeString });

      let extension = 'png';
      if (mimeString === 'image/jpeg') extension = 'jpg';
      if (mimeString === 'image/webp') extension = 'webp';

      const formData = new FormData();
      const cleanFileName = altText.replace(/[^a-z0-9]/gi, '-').toLowerCase().slice(0, 50);
      const fileName = `${cleanFileName}-${Date.now()}.${extension}`;

      formData.append('file', blob, fileName);
      formData.append('alt_text', altText);
      formData.append('title', altText);

      const authHeader = 'Basic ' + btoa(wpConfig.username + ':' + wpConfig.appPassword);
      const baseUrl = getCleanWpUrl(wpConfig.url);

      try {
        const response = await fetch(`${baseUrl}/wp-json/wp/v2/media`, {
            method: 'POST',
            headers: {
                'Authorization': authHeader,
                'Accept': 'application/json',
                // 'Content-Type': 'multipart/form-data' // Intentionally omitted
            },
            body: formData,
            referrerPolicy: 'no-referrer' // Try to avoid referrer blocking
        });

        const responseData = await response.json();

        if (!response.ok) {
            const errorMsg = responseData.message || responseData.code || 'Unknown upload error';
            throw new Error(`Upload Failed: ${errorMsg}`);
        }

        return responseData.source_url; 
      } catch (e: any) {
        if (e.message.includes('Failed to fetch')) {
             throw new Error("CORS/Network Error. Browser blocked the request. Please apply the fix in Help.");
        }
        throw e;
      }
  };

  const handlePublish = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    const fallbackTitle = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;

    if (!wpConfig.url || !wpConfig.username || !wpConfig.appPassword) {
      setShowWpConfig(true);
      return;
    }

    setWpStatus('publishing');
    setErrorMessage(''); 

    try {
      const { title, description, slug, cleanContent } = parseMetaData(rawContent);
      const finalTitle = title || fallbackTitle;

      let contentToUpload = cleanContent;

      const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
      const matches = [...cleanContent.matchAll(imageRegex)];

      if (matches.length > 0) {
          setWpStatus(`uploading_images`);
          for (let i = 0; i < matches.length; i++) {
              const match = matches[i];
              const altText = match[1] || `image-${i}`;
              const base64Data = match[2];

              try {
                  const uploadedUrl = await uploadImageToWP(base64Data, altText, wpConfig);
                  contentToUpload = contentToUpload.replace(base64Data, uploadedUrl);
              } catch (imgErr: any) {
                  console.error("Failed to upload image:", imgErr);
                  throw new Error(`Image Upload Error: ${imgErr.message}`);
              }
          }
      }

      setWpStatus('publishing_post');

      const authHeader = 'Basic ' + btoa(wpConfig.username + ':' + wpConfig.appPassword);
      const baseUrl = getCleanWpUrl(wpConfig.url);

      const postResponse = await fetch(`${baseUrl}/wp-json/wp/v2/posts`, {
          method: 'POST',
          headers: {
              'Content-Type': 'application/json',
              'Authorization': authHeader,
              'Accept': 'application/json'
          },
          body: JSON.stringify({
              title: finalTitle,
              content: contentToUpload, 
              slug: slug || undefined,
              excerpt: description || undefined,
              status: 'draft'
          }),
          referrerPolicy: 'no-referrer'
      });

      const postData = await postResponse.json();

      if (!postResponse.ok) {
        const errorMsg = postData.message || postData.code || "Unknown WP Error";
        throw new Error(`Post Creation Failed: ${errorMsg}`);
      }

      setWpStatus('success');
      setTimeout(() => setWpStatus(''), 5000);

    } catch (e: any) {
      console.error(e);
      setWpStatus('error');
      let msg = e.message;
      if (msg === 'Failed to fetch') {
         msg = "CORS Error. Your WP server blocked the browser request. Check Help.";
      }
      setErrorMessage(msg);
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-8 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm mb-8">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium text-slate-800">{statusMessage}</p>
      <div className="w-full max-w-md bg-gray-200 rounded-full h-2.5 mt-4">
        <div 
          className="bg-blue-600 h-2.5 rounded-full transition-all duration-500" 
          style={{ width: `${totalCount > 0 ? (completedCount / totalCount) * 100 : 0}%` }}
        ></div>
      </div>
      <p className="text-xs mt-2 text-slate-500">Processed {completedCount} of {totalCount} keywords</p>
    </div>
  );

  const PublishButton = () => (
      <div className="flex flex-col items-end">
         <button 
            onClick={handlePublish}
            disabled={wpStatus === 'publishing' || wpStatus === 'uploading_images' || wpStatus === 'publishing_post'}
            className={`flex items-center space-x-2 ${wpStatus === 'error' ? 'bg-red-600 hover:bg-red-700' : 'bg-green-600 hover:bg-green-700'} text-white px-6 py-3 rounded-lg text-lg font-bold shadow-md hover:shadow-lg transition-all disabled:opacity-50`}
         >
           {wpStatus === 'publishing' && <Loader2 className="animate-spin" size={20} />}
           {wpStatus === 'uploading_images' && <span>Uploading Images...</span>}
           {wpStatus === 'publishing_post' && <span>Creating Post...</span>}
           {wpStatus === 'success' && <span>Published! (Draft)</span>}
           {wpStatus === 'error' && <span>Failed (Retry)</span>}
           {!wpStatus && (
               <>
                 <UploadCloud size={20} className="mr-2" />
                 <span>Publish to WordPress</span>
               </>
           )}
         </button>

         {wpStatus === 'error' && errorMessage && (
            <div className="mt-3 max-w-lg text-right animate-in fade-in slide-in-from-top-1">
                <div className="inline-flex items-start text-sm text-red-700 font-medium bg-red-50 p-3 rounded-lg border border-red-200 shadow-sm cursor-pointer hover:bg-red-100 transition-colors" onClick={() => setShowWpConfig(true)}>
                    <AlertTriangle size={16} className="mr-2 mt-0.5 flex-shrink-0" />
                    <span>{errorMessage} (Click to Settings)</span>
                </div>
            </div>
         )}

         {wpStatus === 'success' && (
             <div className="mt-2 text-green-600 font-medium text-sm animate-in fade-in">
                 Successfully created draft! Check your WP Admin.
             </div>
         )}
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">

      <HistorySidebar 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        history={history}
        onSelect={handleSelectHistory}
        onDelete={handleDeleteHistory}
      />

      {viewingHistoryItem && (
        <div className="fixed inset-0 z-50 bg-slate-100 overflow-y-auto">
          <div className="max-w-5xl mx-auto px-4 py-8">
             <div className="flex items-center justify-between mb-6">
                <button 
                  onClick={() => setViewingHistoryItem(null)}
                  className="flex items-center text-slate-600 hover:text-blue-600 font-bold bg-white px-4 py-2 rounded-lg shadow-sm"
                >
                  <ArrowRight className="rotate-180 mr-2" /> Back to Generator
                </button>
                <div className="flex flex-col items-end">
                   <div className="flex items-center space-x-2 mb-2">
                      <span className="text-xs font-bold text-slate-400 uppercase">{viewingHistoryItem.language || 'vi'}</span>
                      <span className="text-sm text-slate-500">Saved on {new Date(viewingHistoryItem.timestamp).toLocaleDateString()}</span>
                   </div>
                   <PublishButton />
                </div>
             </div>
             <ResultViewer 
               title={`[LOG] ${viewingHistoryItem.keyword}`} 
               content={viewingHistoryItem.content} 
               isCollapsible={false}
               onRegenerateImage={handleRegenerateImage}
             />
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center text-white font-bold shadow-md">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight hidden md:block">BestMarathon Wizard</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowHistory(true)}
              className="flex items-center px-3 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <History size={18} className="mr-2" />
              <span className="font-medium">History ({history.length})</span>
            </button>
            <div className="h-6 w-px bg-slate-200 mx-2"></div>
            <button 
              onClick={() => setShowWpConfig(!showWpConfig)}
              className={`p-2 rounded-full transition-colors flex items-center space-x-2 ${connectionTestResult?.success ? 'text-green-600 bg-green-50' : 'text-slate-500 hover:text-blue-600 hover:bg-slate-100'}`}
              title="WordPress Settings"
            >
              <Settings size={20} />
              {connectionTestResult?.success && <span className="text-xs font-bold">Connected</span>}
            </button>
          </div>
        </div>
      </header>

      {/* WP Config Modal */}
      {showWpConfig && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-md overflow-y-auto">
          <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-200 flex justify-between items-center sticky top-0 bg-white rounded-t-xl z-10">
                <h3 className="text-xl font-bold text-slate-800">WordPress Configuration</h3>
                <button onClick={() => setShowWpConfig(false)} className="text-slate-400 hover:text-slate-600"><X size={24} /></button>
            </div>

            <div className="p-6 overflow-y-auto">
                <div className="space-y-5">
                    <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
                        <p className="text-sm text-blue-800 mb-1 font-semibold">Requirement:</p>
                        <p className="text-sm text-blue-700">Use <strong>Application Passwords</strong> (Users &gt; Profile &gt; Application Passwords), not your login password.</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-slate-700 mb-1">Site URL</label>
                            <input 
                            type="text" 
                            value={wpConfig.url}
                            onChange={e => setWpConfig({...wpConfig, url: e.target.value})}
                            placeholder="bestmarathon.vn"
                            className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Username (or Email)</label>
                            <input 
                            type="text" 
                            value={wpConfig.username}
                            onChange={e => setWpConfig({...wpConfig, username: e.target.value})}
                            className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Application Password</label>
                            <input 
                            type="password" 
                            value={wpConfig.appPassword}
                            onChange={e => setWpConfig({...wpConfig, appPassword: e.target.value})}
                            placeholder="xxxx xxxx xxxx xxxx"
                            className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                            />
                        </div>
                    </div>

                    {/* Connection Test */}
                    <div className="flex items-center justify-between pt-2">
                         <button 
                            onClick={testWpConnection}
                            className="flex items-center space-x-2 bg-slate-800 hover:bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                         >
                             <Wifi size={16} /> <span>Test Connection</span>
                         </button>
                         {connectionTestResult && (
