    setShowHistory(false);
  };

  // --- NEW SIMPLIFIED EXPORT LOGIC ---

  const getCleanHtml = (markdownContent: string) => {
      // 1. Remove Meta Data Block
      const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
      let cleanContent = markdownContent.replace(metaBlockRegex, "").trim();

      // 2. Remove Content Markers
      cleanContent = cleanContent
          .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
          .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
          .trim();

      // 3. Convert Markdown to HTML using 'marked'
      // This preserves base64 images within <img> tags
      const htmlContent = marked.parse(cleanContent);
      return htmlContent;
  };

  const handleCopyHtmlCode = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    const html = await getCleanHtml(rawContent); // marked.parse is async in some versions or returns promise

    // Copy to clipboard
    try {
        await navigator.clipboard.writeText(html);
        setCopySuccess('code');
        setTimeout(() => setCopySuccess(''), 3000);
    } catch (err) {
        console.error('Failed to copy', err);
        alert('Failed to copy code. Content might be too large.');
    }
  };

  const handleDownloadHtmlFile = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
    const htmlBody = await getCleanHtml(rawContent);

    const fullHtml = `
<!DOCTYPE html>
<html lang="vi">
<head>
<meta charset="UTF-8">
