                          placeholder="e.g.&#10;Kỷ lục marathon thế giới&#10;Lịch tập chạy 21km&#10;Dinh dưỡng cho runner..."
                          className="w-full h-40 text-lg border border-slate-300 rounded-xl p-4 focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all shadow-sm font-mono text-slate-700 leading-relaxed"
                        />
                        <p className="text-sm text-slate-500 mt-3 flex items-center">
                          <List size={16} className="mr-2" />
                          Enter multiple keywords (one per line).
                        </p>
                     </div>
                  </div>

                  <div className="flex flex-col md:flex-row items-center gap-4 pt-2">
                    <div className="w-full md:w-64">
                       <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
                         <Languages size={16} className="mr-2" /> Output Language
                       </label>
                       <div className="relative">
                         <select
                           value={language}
                           onChange={(e) => setLanguage(e.target.value as OutputLanguage)}
                           className="w-full appearance-none bg-white border border-slate-300 text-slate-700 py-3 px-4 pr-8 rounded-xl leading-tight focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 shadow-sm font-medium"
                         >
                           <option value="vi">Tiếng Việt (Vietnamese)</option>
                           <option value="en">English (Global)</option>
                         </select>
                         <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-500">
                           <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                         </div>
                       </div>
                    </div>

                    <button
                      onClick={handleStartBulk}
                      disabled={!bulkInput.trim()}
                      className="flex-1 w-full md:w-auto mt-6 md:mt-0 flex items-center justify-center px-10 py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-bold text-lg rounded-xl hover:shadow-lg hover:scale-[1.02] active:scale-[0.98] disabled:opacity-70 disabled:hover:scale-100 transition-all"
                    >
                      <Send className="mr-2" size={20} />
                      Start Bulk Automation
                    </button>
                  </div>
                </div>
              </div>
            </section>
          )}

          {status === StepStatus.LOADING && renderLoading()}

          {status === StepStatus.COMPLETE && (
            <div className="bg-green-50 border border-green-200 rounded-xl p-8 text-center animate-in zoom-in duration-300">
               <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                 <Check size={32} />
               </div>
               <h2 className="text-2xl font-bold text-green-800 mb-2">All Tasks Completed!</h2>
               <p className="text-green-700 mb-6">Processed {totalCount} keywords successfully. All articles are saved in History.</p>
               <div className="flex justify-center space-x-4">
                  <button 
                    onClick={() => setShowHistory(true)}
                    className="bg-white border border-green-200 text-green-700 hover:bg-green-100 px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    View History Log
                  </button>
                  <button 
                    onClick={() => {
                       setStatus(StepStatus.IDLE);
                       setBulkInput('');
                       setIdeationResult('');
                       setOutlineResult('');
                       setArticleResult('');
                       setCompletedCount(0);
                       setTotalCount(0);
                    }} 
                    className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    Start New Batch
                  </button>
               </div>
            </div>
          )}

          {(status === StepStatus.LOADING || status === StepStatus.COMPLETE) && (
            <>
              {ideationResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <ResultViewer 
                      title={`Step 2: Ideation (${currentKeyword})`} 
                      content={ideationResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {outlineResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-100">
                    <ResultViewer 
                      title={`Step 3: Outline (${currentKeyword})`} 
                      content={outlineResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {articleResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-200 space-y-6">
                    <ResultViewer 
                      title={`Step 4: Writing (${currentKeyword})`} 
                      content={articleResult} 
                      isCollapsible={true}
                      defaultOpen={true}
                      onRegenerateImage={handleRegenerateImage}
                    />

                    <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex items-center justify-between">
                       <div className="flex items-center space-x-3 text-slate-600">
                          <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                             <Settings size={24} />
                          </div>
                          <div>
                            <p className="font-bold text-slate-800">Done Writing</p>
                            <p className="text-sm text-slate-500">Download and paste to WordPress easily.</p>
                          </div>
                       </div>
                       <ExportActions />
                    </div>
                </section>
              )}
            </>
          )}

          <div ref={bottomRef} />

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { marked } from 'marked';
import JSZip from 'jszip';
import saveAs from 'file-saver';
import { AppStep, StepStatus, WpConfig, HistoryItem, OutputLanguage } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { getHistory, saveHistoryItem, deleteHistoryItem } from './services/storageService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { HistorySidebar } from './components/HistorySidebar';
import { Loader2, Send, Settings, ArrowRight, Check, History, List, X, Languages, Download, Copy, FileText, Package, Code } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [bulkInput, setBulkInput] = useState(''); // Textarea input
  const [language, setLanguage] = useState<OutputLanguage>('vi'); // Language selection

  const [queue, setQueue] = useState<string[]>([]); // Processing queue
  const [completedCount, setCompletedCount] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [currentKeyword, setCurrentKeyword] = useState(''); // Currently processing keyword

  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); 
  const [outlineResult, setOutlineResult] = useState(''); 
  const [articleResult, setArticleResult] = useState(''); 

  // History & Logs
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<HistoryItem | null>(null);

  // Export State
  const [isZipping, setIsZipping] = useState(false);
  const [copyCleanSuccess, setCopyCleanSuccess] = useState(false);

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  // Load History on Mount
  useEffect(() => {
    const loadData = async () => {
        const loadedHistory = await getHistory();
        setHistory(loadedHistory);
    };
    loadData();
  }, []);

  useEffect(() => {
    if (status !== StepStatus.IDLE && bottomRef.current) {
      setTimeout(() => {
          bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  }, [ideationResult, outlineResult, articleResult, status, statusMessage]);

  // --- Bulk Processing Logic ---

  const handleStartBulk = async () => {
    const keywords = bulkInput
      .split('\n')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    if (keywords.length === 0) return;

    setQueue(keywords);
    setTotalCount(keywords.length);
    setCompletedCount(0);
    setStatus(StepStatus.LOADING);

    // Start processing the first keyword, capture current language
    processNextKeyword(keywords, language);
  };

  const processNextKeyword = async (remainingQueue: string[], selectedLang: OutputLanguage) => {
    if (remainingQueue.length === 0) {
      setStatus(StepStatus.COMPLETE);
      setStatusMessage("All keywords processed successfully!");
      setCurrentKeyword('');
      return;
    }

    const keyword = remainingQueue[0];
    const nextQueue = remainingQueue.slice(1);

    setCurrentKeyword(keyword);
    setQueue(nextQueue);
    setCompletedCount(prev => totalCount - remainingQueue.length);

    // Reset UI for new keyword
    setCurrentStep(AppStep.INPUT);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');
    resetSession();

    try {
      const langLabel = selectedLang === 'vi' ? 'VI' : 'EN';

      // --- Step 1 ---
      setStatusMessage(`[${keyword}][${langLabel}] Researching data (Step 1/4)...`);
      await executeStep1(keyword, selectedLang);

      // --- Step 2 ---
      setStatusMessage(`[${keyword}][${langLabel}] Generating Ideation (Step 2/4)...`);
      const ideation = await executeStep2(keyword, selectedLang);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // --- Step 3 ---
      setStatusMessage(`[${keyword}][${langLabel}] Creating Outline (Step 3/4)...`);
      const outline = await executeStep3(selectedLang);
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // --- Step 4 ---
      setStatusMessage(`[${keyword}][${langLabel}] Writing Article (Step 4/4)...`);
      const rawArticle = await executeStep4(keyword, selectedLang);
      setArticleResult(rawArticle);
      setCurrentStep(AppStep.WRITING);

      // --- Images ---
      setStatusMessage(`[${keyword}] Generating Images (Vietnamese Context)...`);
      // Updated Regex to support [HÌNH ẢNH: ...] based on new prompt
      const imageRegex = /\[(?:IMAGE_PROMPT|HÌNH ẢNH):\s*(.*?)\]/gi;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;
        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`[${keyword}] Image ${processedCount + 1}/${matches.length}...`);
            const base64Image = await generateBlogImage(prompt);
            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``);
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      // --- Save to History ---
      const newItem: HistoryItem = {
        id: "", // Service will assign unique ID
        keyword: keyword,
        content: finalArticle,
        timestamp: Date.now(),
        language: selectedLang
      };

      console.log("Saving article to DB...");
      const updatedHistory = await saveHistoryItem(newItem);
      setHistory(updatedHistory);

      // --- Trigger Next ---
      setCompletedCount(prev => prev + 1);

      // Small delay between articles to avoid rate limits abruptly
      setStatusMessage(`[${keyword}] Finished! Starting next in 3s...`);
      await new Promise(r => setTimeout(r, 3000));

      processNextKeyword(nextQueue, selectedLang);

    } catch (error) {
      console.error(error);
      const errorItem: HistoryItem = {
        id: "",
        keyword: keyword + " (FAILED)",
        content: `Error processing: ${error}`,
        timestamp: Date.now(),
        language: selectedLang
      };
      const updatedHistory = await saveHistoryItem(errorItem);
      setHistory(updatedHistory);

      setStatusMessage(`Error with "${keyword}". Moving to next...`);
      await new Promise(r => setTimeout(r, 2000));
      processNextKeyword(nextQueue, selectedLang);
    }
  };

  // --- REGENERATE IMAGE LOGIC ---
  const handleRegenerateImage = async (oldSrc: string, altText: string) => {
      // Find the current content (either live or viewing history)
      const currentContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;

      // Generate new image
      const newBase64 = await generateBlogImage(altText);

      if (newBase64) {
          // Replace in content string
          const newContent = currentContent.replace(oldSrc, newBase64);

          if (viewingHistoryItem) {
              const updatedItem = { ...viewingHistoryItem, content: newContent };
              setViewingHistoryItem(updatedItem);
              const updatedHistory = await saveHistoryItem(updatedItem);
              setHistory(updatedHistory);
          } else {
              setArticleResult(newContent);
              const existingItem = history.find(h => h.keyword === currentKeyword);
              if (existingItem) {
                  const updatedItem = { ...existingItem, content: newContent };
                  const updatedHistory = await saveHistoryItem(updatedItem);
                  setHistory(updatedHistory);
              }
          }
      } else {
          alert("Could not regenerate image. Please try again.");
      }
  };

  // History Handlers
  const handleDeleteHistory = async (id: string) => {
    const updated = await deleteHistoryItem(id);
    setHistory(updated);
    if (viewingHistoryItem?.id === id) setViewingHistoryItem(null);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setViewingHistoryItem(item);
    setShowHistory(false);
  };

  // --- EXPORT LOGIC ---

  const cleanContentForExport = (markdownContent: string) => {
      const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
      let cleanContent = markdownContent.replace(metaBlockRegex, "").trim();
      cleanContent = cleanContent
          .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
          .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
          .trim();
      return cleanContent;
  };

  const handleCopyCleanHtml = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    let cleanMD = cleanContentForExport(rawContent);

    // Convert to HTML first using marked
    let html = await marked.parse(cleanMD);

    // Replace Base64 images with Placeholders using Regex on HTML
    // Pattern matches <img src="data:..." alt="..." ... >
    let imgIndex = 1;
    html = html.replace(/<img[^>]*src=["']data:[^"']*["'][^>]*alt=["']([^"']*)["'][^>]*>/gi, (match, alt) => {
         const placeholder = `<div style="background-color: #f8fafc; border: 2px dashed #cbd5e1; padding: 20px; text-align: center; margin: 20px 0; border-radius: 8px;">
            <p style="font-weight: bold; color: #1e40af; margin-bottom: 5px;">[CHÈN ẢNH ${imgIndex}: image-${imgIndex}.png]</p>
            <p style="color: #64748b; font-size: 0.9em; font-style: italic;">Alt Text: ${alt}</p>
         </div>`;
         imgIndex++;
         return placeholder;
    });

    try {
        await navigator.clipboard.writeText(html);
        setCopyCleanSuccess(true);
        setTimeout(() => setCopyCleanSuccess(false), 3000);
    } catch (err) {
        console.error('Failed to copy', err);
        alert('Failed to copy code.');
    }
  };

  const handleDownloadPackage = async () => {
    setIsZipping(true);
    try {
        const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
        const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
        const safeKeyword = keyword.replace(/[^a-zA-Z0-9\s-_]/g, '').trim().replace(/\s+/g, '-');

        const zip = new JSZip();

        // 1. Extract Images and Clean Markdown
        const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
        let cleanMD = cleanContentForExport(rawContent);

        let imgIndex = 1;
        const matches = [...cleanContentForExport(rawContent).matchAll(imageRegex)];

        // Create images folder
        const imgFolder = zip.folder("images");

        // Loop through images to process
        for (const match of matches) {
            const originalTag = match[0];
            const altText = match[1] || `image-${imgIndex}`;
            const base64Full = match[2];

            // Extract pure base64
            const base64Data = base64Full.split(',')[1];
            const mimeType = base64Full.split(';')[0].split(':')[1];
            const ext = mimeType === 'image/jpeg' ? 'jpg' : 'png';

            // STRICT NAMING: image-1.png, image-2.png
            const fileName = `image-${imgIndex}.${ext}`;

            // Add to zip
            imgFolder?.file(fileName, base64Data, {base64: true});

            // Replace text in MD for clarity
            cleanMD = cleanMD.replace(originalTag, `\n> [CHÈN ẢNH ${imgIndex}: images/${fileName}]\n> Alt: ${altText}\n`);

            imgIndex++;
        }

        // 2. Add Text Content
        zip.file(`${safeKeyword}-content.txt`, cleanMD);

        // 3. Add Word Doc (With embedded images for easy copy paste)
        const docHtml = `
          <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
          <head><meta charset="utf-8"></head>
          <body>${await marked.parse(cleanContentForExport(rawContent))}</body>
          </html>`;
        zip.file(`${safeKeyword}-visual-editor.doc`, docHtml);

        // 4. Generate
        const content = await zip.generateAsync({type: "blob"});
        saveAs(content, `BestMarathon-${safeKeyword}.zip`);

    } catch (e) {
        console.error("Zip Error", e);
        alert("Failed to create zip package");
    } finally {
        setIsZipping(false);
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-8 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm mb-8">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-blue-600" />
      <p className="text-lg font-medium text-slate-800">{statusMessage}</p>
      <div className="w-full max-w-md bg-gray-200 rounded-full h-2.5 mt-4">
        <div 
          className="bg-blue-600 h-2.5 rounded-full transition-all duration-500" 
          style={{ width: `${totalCount > 0 ? (completedCount / totalCount) * 100 : 0}%` }}
        ></div>
      </div>
      <p className="text-xs mt-2 text-slate-500">Processed {completedCount} of {totalCount} keywords</p>
    </div>
  );

  // New "Manual Export" Component
  const ExportActions = () => (
      <div className="flex flex-col space-y-3 items-end">

         <div className="text-sm text-slate-500 mb-2 font-medium">Export Options:</div>

         <div className="flex flex-wrap gap-3 justify-end">
             {/* Option 1: Clean HTML (New request) */}
             <button 
                onClick={handleCopyCleanHtml}
                className="flex items-center space-x-2 bg-slate-100 hover:bg-slate-200 text-slate-800 border border-slate-300 px-4 py-3 rounded-lg font-bold shadow-sm transition-all active:scale-95"
                title="Copy HTML code without huge base64 strings. Images are marked as placeholders."
             >
                {copyCleanSuccess ? <Check size={20} className="text-green-600"/> : <Code size={20} />}
                <span>Copy Clean HTML</span>
             </button>

             {/* Option 2: Full Package */}
             <button 
                onClick={handleDownloadPackage}
                disabled={isZipping}
                className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-3 rounded-lg font-bold shadow-md transition-all active:scale-95 disabled:opacity-70"
                title="Download ZIP with separate named images (image-1.png, etc)"
             >
                {isZipping ? <Loader2 size={20} className="animate-spin" /> : <Package size={20} />}
                <span>Download All (.zip)</span>
             </button>
         </div>

         {copyCleanSuccess && (
             <div className="text-green-600 text-sm font-semibold animate-in fade-in slide-in-from-top-1">
                 Copied Clean HTML! Paste into WordPress Code Editor.
             </div>
         )}

         <div className="text-xs text-slate-500 bg-white p-3 rounded-lg border border-slate-200 shadow-sm max-w-sm text-right">
             <p className="mb-1"><strong>New:</strong> Use "Download All" to get images named <code>image-1.png</code>.</p>
             <p>Use "Copy Clean HTML" to paste code without lag, then upload images to the marked spots.</p>
         </div>
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">

      <HistorySidebar 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        history={history}
        onSelect={handleSelectHistory}
        onDelete={handleDeleteHistory}
      />

      {viewingHistoryItem && (
        <div className="fixed inset-0 z-50 bg-slate-100 overflow-y-auto">
          <div className="max-w-5xl mx-auto px-4 py-8">
             <div className="flex items-center justify-between mb-6">
                <button 
                  onClick={() => setViewingHistoryItem(null)}
                  className="flex items-center text-slate-600 hover:text-blue-600 font-bold bg-white px-4 py-2 rounded-lg shadow-sm"
                >
                  <ArrowRight className="rotate-180 mr-2" /> Back to Generator
                </button>
                <div className="flex flex-col items-end">
                   <div className="flex items-center space-x-2 mb-2">
                      <span className="text-xs font-bold text-slate-400 uppercase">{viewingHistoryItem.language || 'vi'}</span>
                      <span className="text-sm text-slate-500">Saved on {new Date(viewingHistoryItem.timestamp).toLocaleDateString()}</span>
                   </div>
                   <ExportActions />
                </div>
             </div>
             <ResultViewer 
               title={`[LOG] ${viewingHistoryItem.keyword}`} 
               content={viewingHistoryItem.content} 
               isCollapsible={false}
               onRegenerateImage={handleRegenerateImage}
             />
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center text-white font-bold shadow-md">
              AI
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight hidden md:block">BestMarathon Wizard</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowHistory(true)}
              className="flex items-center px-3 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <History size={18} className="mr-2" />
              <span className="font-medium">History ({history.length})</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className={`flex-1 max-w-5xl mx-auto w-full px-4 pb-20 pt-6 transition-opacity ${viewingHistoryItem ? 'opacity-0 pointer-events-none fixed' : 'opacity-100'}`}>

        {status !== StepStatus.IDLE && status !== StepStatus.COMPLETE && (
           <StepIndicator currentStep={currentStep} />
        )}

        <div className="space-y-8 mt-6">

          {status === StepStatus.IDLE && (
            <section className="animate-in fade-in zoom-in duration-300">
              <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100">
                <div className="flex items-center justify-between mb-6">
                   <div className="flex items-center">
                     <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-lg mr-4">1</div>
                     <h2 className="text-2xl font-bold text-slate-800">Bulk Keywords</h2>
                   </div>
                </div>

                <div className="space-y-6 ml-14">
                  <div className="flex space-x-4">
                     <div className="flex-1">
                        <textarea
                          value={bulkInput}
                          onChange={(e) => setBulkInput(e.target.value)}
                          placeholder="e.g.&#10;Kỷ lục marathon thế giới&#10;Lịch tập chạy 21km&#10;Dinh dưỡng cho runner..."
                          className="w-full h-40 text-lg border border-slate-300 rounded-xl p-4 focus:ring-4 focus:ring-blue-50 focus:border-blue-500 outline-none transition-all shadow-sm font-mono text-slate-700 leading-relaxed"
                        />
                        <p className="text-sm text-slate-500 mt-3 flex items-center">
                          <List size={16} className="mr-2" />
                          Enter multiple keywords (one per line).
                        </p>
                     </div>
                  </div>

                  <div className="flex flex-col md:flex-row items-center gap-4 pt-2">
                    <div className="w-full md:w-64">
                       <label className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
                         <Languages size={16} className="mr-2" /> Output Language
                       </label>
                       <div className="relative">
                         <select
                           value={language}
                           onChange={(e) => setLanguage(e.target.value as OutputLanguage)}
                           className="w-full appearance-none bg-white border border-slate-300 text-slate-700 py-3 px-4 pr-8 rounded-xl leading-tight focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 shadow-sm font-medium"
                         >
                           <option value="vi">Tiếng Việt (Vietnamese)</option>
                           <option value="en">English (Global)</option>
                         </select>
                         <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-slate-500">
                           <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                         </div>
                       </div>
                    </div>

                    <button
                      onClick={handleStartBulk}
                      disabled={!bulkInput.trim()}
                      className="flex-1 w-full md:w-auto mt-6 md:mt-0 flex items-center justify-center px-10 py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-bold text-lg rounded-xl hover:shadow-lg hover:scale-[1.02] active:scale-[0.98] disabled:opacity-70 disabled:hover:scale-100 transition-all"
                    >
                      <Send className="mr-2" size={20} />
                      Start Bulk Automation
                    </button>
                  </div>
                </div>
              </div>
            </section>
          )}

          {status === StepStatus.LOADING && renderLoading()}

          {status === StepStatus.COMPLETE && (
            <div className="bg-green-50 border border-green-200 rounded-xl p-8 text-center animate-in zoom-in duration-300">
               <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                 <Check size={32} />
               </div>
               <h2 className="text-2xl font-bold text-green-800 mb-2">All Tasks Completed!</h2>
               <p className="text-green-700 mb-6">Processed {totalCount} keywords successfully. All articles are saved in History.</p>
               <div className="flex justify-center space-x-4">
                  <button 
                    onClick={() => setShowHistory(true)}
                    className="bg-white border border-green-200 text-green-700 hover:bg-green-100 px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    View History Log
                  </button>
                  <button 
                    onClick={() => {
                       setStatus(StepStatus.IDLE);
                       setBulkInput('');
                       setIdeationResult('');
                       setOutlineResult('');
                       setArticleResult('');
                       setCompletedCount(0);
                       setTotalCount(0);
                    }} 
                    className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold transition-colors"
                  >
                    Start New Batch
                  </button>
               </div>
            </div>
          )}

          {(status === StepStatus.LOADING || status === StepStatus.COMPLETE) && (
            <>
              {ideationResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <ResultViewer 
                      title={`Step 2: Ideation (${currentKeyword})`} 
                      content={ideationResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {outlineResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-100">
                    <ResultViewer 
                      title={`Step 3: Outline (${currentKeyword})`} 
                      content={outlineResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {articleResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-200 space-y-6">
                    <ResultViewer 
                      title={`Step 4: Writing (${currentKeyword})`} 
                      content={articleResult} 
                      isCollapsible={true}
                      defaultOpen={true}
                      onRegenerateImage={handleRegenerateImage}
                    />

                    <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex items-center justify-between">
                       <div className="flex items-center space-x-3 text-slate-600">
                          <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
                             <Settings size={24} />
                          </div>
                          <div>
                            <p className="font-bold text-slate-800">Done Writing</p>
                            <p className="text-sm text-slate-500">Download and paste to WordPress easily.</p>
                          </div>
                       </div>
                       <ExportActions />
                    </div>
                </section>
              )}
            </>
          )}

          <div ref={bottomRef} />

        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { AppStep } from '../types';
import { Check } from 'lucide-react';

interface Props {
  currentStep: AppStep;
}

const steps = [
  { id: AppStep.INPUT, label: 'Input' },
  { id: AppStep.IDEATION, label: 'Ideation' },
  { id: AppStep.OUTLINE, label: 'Outline' },
  { id: AppStep.WRITING, label: 'Writing' },
  { id: AppStep.PUBLISH, label: 'Publish' },
];

export const StepIndicator: React.FC<Props> = ({ currentStep }) => {
  return (
    <div className="w-full py-6">
      <div className="flex items-center justify-center space-x-2 md:space-x-4">
        {steps.map((step, index) => {
          const isCompleted = currentStep > step.id;
          const isCurrent = currentStep === step.id;

          return (
            <div key={step.id} className="flex items-center">
              <div
                className={`flex items-center space-x-2 ${
                  isCompleted ? 'text-green-600' : isCurrent ? 'text-orange-600' : 'text-slate-400'
                }`}
              >
                <div 
                  className={`
                    flex items-center justify-center w-8 h-8 rounded-full border-2 transition-all duration-300
                    ${isCompleted 
                      ? 'bg-green-100 border-green-600' 
                      : isCurrent 
                        ? 'bg-orange-50 border-orange-500 shadow-[0_0_10px_rgba(255,165,0,0.3)]' 
                        : 'bg-slate-50 border-slate-300'
                    }
                  `}
                >
                  {isCompleted ? <Check size={16} /> : <span className="text-sm font-bold">{step.id}</span>}
                </div>
                <span className={`hidden sm:block text-sm font-medium ${isCurrent ? 'font-bold' : ''}`}>
                  {step.label}
                </span>
              </div>
              {index < steps.length - 1 && (
                <div className={`w-8 md:w-12 h-0.5 mx-2 md:mx-4 transition-colors duration-300 ${
                  isCompleted ? 'bg-green-600' : isCurrent ? 'bg-gradient-to-r from-orange-400 to-slate-200' : 'bg-slate-200'
                }`} />
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { marked } from 'marked';
import JSZip from 'jszip';
import saveAs from 'file-saver';
import { AppStep, StepStatus, WpConfig, HistoryItem, OutputLanguage } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { getHistory, saveHistoryItem, deleteHistoryItem } from './services/storageService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { HistorySidebar } from './components/HistorySidebar';
import { Loader2, Send, Settings, ArrowRight, Check, History, List, X, Languages, Download, Copy, FileText, Package, Code, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [bulkInput, setBulkInput] = useState(''); // Textarea input
  const [language, setLanguage] = useState<OutputLanguage>('vi'); // Language selection

  const [queue, setQueue] = useState<string[]>([]); // Processing queue
  const [completedCount, setCompletedCount] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [currentKeyword, setCurrentKeyword] = useState(''); // Currently processing keyword

  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); 
  const [outlineResult, setOutlineResult] = useState(''); 
  const [articleResult, setArticleResult] = useState(''); 

  // History & Logs
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<HistoryItem | null>(null);

  // Export State
  const [isZipping, setIsZipping] = useState(false);
  const [copyCleanSuccess, setCopyCleanSuccess] = useState(false);

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  // Constants for Style
  const GOLD_GRADIENT = 'linear-gradient(135deg, rgb(255, 215, 0), rgb(255, 165, 0))';

  // Load History on Mount
  useEffect(() => {
    const loadData = async () => {
        const loadedHistory = await getHistory();
        setHistory(loadedHistory);
    };
    loadData();
  }, []);

  useEffect(() => {
    if (status !== StepStatus.IDLE && bottomRef.current) {
      setTimeout(() => {
          bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  }, [ideationResult, outlineResult, articleResult, status, statusMessage]);

  // --- Bulk Processing Logic ---

  const handleStartBulk = async () => {
    const keywords = bulkInput
      .split('\n')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    if (keywords.length === 0) return;

    setQueue(keywords);
    setTotalCount(keywords.length);
    setCompletedCount(0);
    setStatus(StepStatus.LOADING);

    // Start processing the first keyword, capture current language
    processNextKeyword(keywords, language);
  };

  const processNextKeyword = async (remainingQueue: string[], selectedLang: OutputLanguage) => {
    if (remainingQueue.length === 0) {
      setStatus(StepStatus.COMPLETE);
      setStatusMessage("All keywords processed successfully!");
      setCurrentKeyword('');
      return;
    }

    const keyword = remainingQueue[0];
    const nextQueue = remainingQueue.slice(1);

    setCurrentKeyword(keyword);
    setQueue(nextQueue);
    setCompletedCount(prev => totalCount - remainingQueue.length);

    // Reset UI for new keyword
    setCurrentStep(AppStep.INPUT);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');
    resetSession();

    try {
      const langLabel = selectedLang === 'vi' ? 'VI' : 'EN';

      // --- Step 1 ---
      setStatusMessage(`[${keyword}][${langLabel}] Researching data (Step 1/4)...`);
      await executeStep1(keyword, selectedLang);

      // --- Step 2 ---
      setStatusMessage(`[${keyword}][${langLabel}] Generating Ideation (Step 2/4)...`);
      const ideation = await executeStep2(keyword, selectedLang);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // --- Step 3 ---
      setStatusMessage(`[${keyword}][${langLabel}] Creating Outline (Step 3/4)...`);
      const outline = await executeStep3(selectedLang);
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // --- Step 4 ---
      setStatusMessage(`[${keyword}][${langLabel}] Writing Article (Step 4/4)...`);
      const rawArticle = await executeStep4(keyword, selectedLang);
      setArticleResult(rawArticle);
      setCurrentStep(AppStep.WRITING);

      // --- Images ---
      setStatusMessage(`[${keyword}] Generating Images (Vietnamese Context)...`);
      // Updated Regex to support [HÌNH ẢNH: ...] based on new prompt
      const imageRegex = /\[(?:IMAGE_PROMPT|HÌNH ẢNH):\s*(.*?)\]/gi;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;
        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`[${keyword}] Image ${processedCount + 1}/${matches.length}...`);
            const base64Image = await generateBlogImage(prompt);
            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``);
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      // --- Save to History ---
      const newItem: HistoryItem = {
        id: "", // Service will assign unique ID
        keyword: keyword,
        content: finalArticle,
        timestamp: Date.now(),
        language: selectedLang
      };

      console.log("Saving article to DB...");
      const updatedHistory = await saveHistoryItem(newItem);
      setHistory(updatedHistory);

      // --- Trigger Next ---
      setCompletedCount(prev => prev + 1);

      // Small delay between articles to avoid rate limits abruptly
      setStatusMessage(`[${keyword}] Finished! Starting next in 3s...`);
      await new Promise(r => setTimeout(r, 3000));

      processNextKeyword(nextQueue, selectedLang);

    } catch (error) {
      console.error(error);
      const errorItem: HistoryItem = {
        id: "",
        keyword: keyword + " (FAILED)",
        content: `Error processing: ${error}`,
        timestamp: Date.now(),
        language: selectedLang
      };
      const updatedHistory = await saveHistoryItem(errorItem);
      setHistory(updatedHistory);

      setStatusMessage(`Error with "${keyword}". Moving to next...`);
      await new Promise(r => setTimeout(r, 2000));
      processNextKeyword(nextQueue, selectedLang);
    }
  };

  // --- REGENERATE IMAGE LOGIC ---
  const handleRegenerateImage = async (oldSrc: string, altText: string) => {
      // Find the current content (either live or viewing history)
      const currentContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;

      // Generate new image
      const newBase64 = await generateBlogImage(altText);

      if (newBase64) {
          // Replace in content string
          const newContent = currentContent.replace(oldSrc, newBase64);

          if (viewingHistoryItem) {
              const updatedItem = { ...viewingHistoryItem, content: newContent };
              setViewingHistoryItem(updatedItem);
              const updatedHistory = await saveHistoryItem(updatedItem);
              setHistory(updatedHistory);
          } else {
              setArticleResult(newContent);
              const existingItem = history.find(h => h.keyword === currentKeyword);
              if (existingItem) {
                  const updatedItem = { ...existingItem, content: newContent };
                  const updatedHistory = await saveHistoryItem(updatedItem);
                  setHistory(updatedHistory);
              }
          }
      } else {
          alert("Could not regenerate image. Please try again.");
      }
  };

  // History Handlers
  const handleDeleteHistory = async (id: string) => {
    const updated = await deleteHistoryItem(id);
    setHistory(updated);
    if (viewingHistoryItem?.id === id) setViewingHistoryItem(null);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setViewingHistoryItem(item);
    setShowHistory(false);
  };

  // --- EXPORT LOGIC ---

  const cleanContentForExport = (markdownContent: string) => {
      const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
      let cleanContent = markdownContent.replace(metaBlockRegex, "").trim();
      cleanContent = cleanContent
          .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
          .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
          .trim();
      return cleanContent;
  };

  const handleCopyCleanHtml = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    let cleanMD = cleanContentForExport(rawContent);

    // Convert to HTML first using marked
    let html = await marked.parse(cleanMD);

    // Replace Base64 images with Placeholders using Regex on HTML
    // Pattern matches <img src="data:..." alt="..." ... >
    let imgIndex = 1;
    html = html.replace(/<img[^>]*src=["']data:[^"']*["'][^>]*alt=["']([^"']*)["'][^>]*>/gi, (match, alt) => {
         const placeholder = `<div style="background-color: #f8fafc; border: 2px dashed #cbd5e1; padding: 20px; text-align: center; margin: 20px 0; border-radius: 8px;">
            <p style="font-weight: bold; color: #1e40af; margin-bottom: 5px;">[CHÈN ẢNH ${imgIndex}: image-${imgIndex}.png]</p>
            <p style="color: #64748b; font-size: 0.9em; font-style: italic;">Alt Text: ${alt}</p>
         </div>`;
         imgIndex++;
         return placeholder;
    });

    try {
        await navigator.clipboard.writeText(html);
        setCopyCleanSuccess(true);
        setTimeout(() => setCopyCleanSuccess(false), 3000);
    } catch (err) {
        console.error('Failed to copy', err);
        alert('Failed to copy code.');
    }
  };

  const handleDownloadPackage = async () => {
    setIsZipping(true);
    try {
        const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
        const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
        const safeKeyword = keyword.replace(/[^a-zA-Z0-9\s-_]/g, '').trim().replace(/\s+/g, '-');

        const zip = new JSZip();

        // 1. Extract Images and Clean Markdown
        const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
        let cleanMD = cleanContentForExport(rawContent);

        let imgIndex = 1;
        const matches = [...cleanContentForExport(rawContent).matchAll(imageRegex)];

        // Create images folder
        const imgFolder = zip.folder("images");

        // Loop through images to process
        for (const match of matches) {
            const originalTag = match[0];
            const altText = match[1] || `image-${imgIndex}`;
            const base64Full = match[2];

            // Extract pure base64
            const base64Data = base64Full.split(',')[1];
            const mimeType = base64Full.split(';')[0].split(':')[1];
            const ext = mimeType === 'image/jpeg' ? 'jpg' : 'png';

            // STRICT NAMING: image-1.png, image-2.png
            const fileName = `image-${imgIndex}.${ext}`;

            // Add to zip
            imgFolder?.file(fileName, base64Data, {base64: true});

            // Replace text in MD for clarity
            cleanMD = cleanMD.replace(originalTag, `\n> [CHÈN ẢNH ${imgIndex}: images/${fileName}]\n> Alt: ${altText}\n`);

            imgIndex++;
        }

        // 2. Add Text Content
        zip.file(`${safeKeyword}-content.txt`, cleanMD);

        // 3. Add Word Doc (With embedded images for easy copy paste)
        const docHtml = `
          <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
          <head><meta charset="utf-8"></head>
          <body>${await marked.parse(cleanContentForExport(rawContent))}</body>
          </html>`;
        zip.file(`${safeKeyword}-visual-editor.doc`, docHtml);

        // 4. Generate
        const content = await zip.generateAsync({type: "blob"});
        saveAs(content, `BestMarathon-${safeKeyword}.zip`);

    } catch (e) {
        console.error("Zip Error", e);
        alert("Failed to create zip package");
    } finally {
        setIsZipping(false);
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-8 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm mb-8">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-orange-500" />
      <p className="text-lg font-medium text-slate-800">{statusMessage}</p>
      <div className="w-full max-w-md bg-slate-100 rounded-full h-2.5 mt-4 overflow-hidden">
        <div 
          className="h-2.5 rounded-full transition-all duration-500" 
          style={{ 
            width: `${totalCount > 0 ? (completedCount / totalCount) * 100 : 0}%`,
            background: GOLD_GRADIENT 
          }}
        ></div>
      </div>
      <p className="text-xs mt-2 text-slate-500">Processed {completedCount} of {totalCount} keywords</p>
    </div>
  );

  // New "Manual Export" Component
  const ExportActions = () => (
      <div className="flex flex-col space-y-3 items-end">

         <div className="text-sm text-slate-500 mb-2 font-medium">Export Options:</div>

         <div className="flex flex-wrap gap-3 justify-end">
             {/* Option 1: Clean HTML (New request) */}
             <button 
                onClick={handleCopyCleanHtml}
                className="flex items-center space-x-2 bg-slate-50 hover:bg-slate-100 text-slate-700 border border-slate-200 px-4 py-3 rounded-lg font-bold shadow-sm transition-all active:scale-95"
                title="Copy HTML code without huge base64 strings. Images are marked as placeholders."
             >
                {copyCleanSuccess ? <Check size={20} className="text-green-600"/> : <Code size={20} />}
                <span>Copy Clean HTML</span>
             </button>

             {/* Option 2: Full Package */}
             <button 
                onClick={handleDownloadPackage}
                disabled={isZipping}
                className="flex items-center space-x-2 text-white px-5 py-3 rounded-lg font-bold shadow-md transition-all active:scale-95 disabled:opacity-70 disabled:grayscale"
                style={{ background: GOLD_GRADIENT }}
                title="Download ZIP with separate named images (image-1.png, etc)"
             >
                {isZipping ? <Loader2 size={20} className="animate-spin" /> : <Package size={20} />}
                <span>Download All (.zip)</span>
             </button>
         </div>

         {copyCleanSuccess && (
             <div className="text-green-600 text-sm font-semibold animate-in fade-in slide-in-from-top-1">
                 Copied Clean HTML! Paste into WordPress Code Editor.
             </div>
         )}

         <div className="text-xs text-slate-500 bg-white p-3 rounded-lg border border-slate-200 shadow-sm max-w-sm text-right">
             <p className="mb-1"><strong>New:</strong> Use "Download All" to get images named <code>image-1.png</code>.</p>
             <p>Use "Copy Clean HTML" to paste code without lag, then upload images to the marked spots.</p>
         </div>
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">

      <HistorySidebar 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        history={history}
        onSelect={handleSelectHistory}
        onDelete={handleDeleteHistory}
      />

      {viewingHistoryItem && (
        <div className="fixed inset-0 z-50 bg-slate-100 overflow-y-auto">
          <div className="max-w-5xl mx-auto px-4 py-8">
             <div className="flex items-center justify-between mb-6">
                <button 
                  onClick={() => setViewingHistoryItem(null)}
                  className="flex items-center text-slate-600 hover:text-orange-600 font-bold bg-white px-4 py-2 rounded-lg shadow-sm border border-slate-200"
                >
                  <ArrowRight className="rotate-180 mr-2" /> Back to Generator
                </button>
                <div className="flex flex-col items-end">
                   <div className="flex items-center space-x-2 mb-2">
                      <span className="text-xs font-bold text-slate-400 uppercase">{viewingHistoryItem.language || 'vi'}</span>
                      <span className="text-sm text-slate-500">Saved on {new Date(viewingHistoryItem.timestamp).toLocaleDateString()}</span>
                   </div>
                   <ExportActions />
                </div>
             </div>
             <ResultViewer 
               title={`[LOG] ${viewingHistoryItem.keyword}`} 
               content={viewingHistoryItem.content} 
               isCollapsible={false}
               onRegenerateImage={handleRegenerateImage}
             />
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm/50 backdrop-blur-md bg-white/90">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div 
              className="w-10 h-10 rounded-xl flex items-center justify-center text-white font-bold shadow-lg"
              style={{ background: GOLD_GRADIENT }}
            >
              <Sparkles size={20} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight hidden md:block">BestMarathon Wizard</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowHistory(true)}
              className="flex items-center px-4 py-2 text-slate-600 hover:bg-orange-50 hover:text-orange-700 rounded-full transition-all border border-transparent hover:border-orange-100 font-medium text-sm group"
            >
              <History size={18} className="mr-2 group-hover:text-orange-500" />
              <span>History ({history.length})</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className={`flex-1 max-w-5xl mx-auto w-full px-4 pb-20 pt-6 transition-opacity ${viewingHistoryItem ? 'opacity-0 pointer-events-none fixed' : 'opacity-100'}`}>

        {status !== StepStatus.IDLE && status !== StepStatus.COMPLETE && (
           <StepIndicator currentStep={currentStep} />
        )}

        <div className="space-y-8 mt-6">

          {status === StepStatus.IDLE && (
            <section className="animate-in fade-in zoom-in duration-300">
              <div className="bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden relative">
                {/* Decorative Top Bar */}
                <div className="h-1.5 w-full" style={{ background: GOLD_GRADIENT }}></div>

                <div className="p-8 md:p-10">
                  <div className="flex items-center justify-between mb-8">
                     <div className="flex items-center">
                       <div 
                          className="w-12 h-12 rounded-full flex items-center justify-center font-bold text-xl mr-5 shadow-inner"
                          style={{ background: 'rgba(255, 165, 0, 0.1)', color: 'rgb(255, 140, 0)' }}
                        >
                          1
                       </div>
                       <div>
                          <h2 className="text-2xl font-bold text-slate-800">Keyword Input</h2>
                          <p className="text-slate-500 text-sm mt-1">Enter topics to generate SEO optimized content.</p>
                       </div>
                     </div>
                  </div>

                  <div className="space-y-6">
                    <div className="relative group">
                       <textarea
                         value={bulkInput}
                         onChange={(e) => setBulkInput(e.target.value)}
                         placeholder="e.g.&#10;Kỷ lục marathon thế giới&#10;Lịch tập chạy 21km&#10;Dinh dưỡng cho runner..."
                         className="w-full h-48 text-lg border border-slate-200 rounded-xl p-5 focus:ring-4 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all shadow-sm font-mono text-slate-700 leading-relaxed resize-none bg-slate-50 group-hover:bg-white"
                       />
                       <div className="absolute top-4 right-4 pointer-events-none text-slate-300">
                          <List size={20} />
                       </div>
                    </div>

                    <div className="flex flex-col md:flex-row items-stretch gap-4 pt-2">
                      <div className="w-full md:w-1/3">
                         <div className="relative h-full">
                           <select
                             value={language}
                             onChange={(e) => setLanguage(e.target.value as OutputLanguage)}
                             className="w-full h-full appearance-none bg-white border border-slate-200 text-slate-700 py-3.5 px-5 pr-10 rounded-xl leading-tight focus:outline-none focus:ring-2 focus:ring-orange-200 focus:border-orange-400 shadow-sm font-medium cursor-pointer hover:border-orange-300 transition-colors"
                           >
                             <option value="vi">🇻🇳 Tiếng Việt (Vietnamese)</option>
                             <option value="en">🇬🇧 English (Global)</option>
                           </select>
                           <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-slate-400">
                             <Languages size={18} />
                           </div>
                         </div>
                      </div>

                      <button
                        onClick={handleStartBulk}
                        disabled={!bulkInput.trim()}
                        className="flex-1 w-full flex items-center justify-center px-8 py-4 text-white font-bold text-lg rounded-xl shadow-lg hover:shadow-xl hover:scale-[1.01] active:scale-[0.99] disabled:opacity-60 disabled:hover:scale-100 transition-all uppercase tracking-wide"
                        style={{ 
                          background: GOLD_GRADIENT,
                          textShadow: '0 1px 2px rgba(0,0,0,0.1)'
                        }}
                      >
                        <Send className="mr-3" size={22} />
                        Start Automation
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          )}

          {status === StepStatus.LOADING && renderLoading()}

          {status === StepStatus.COMPLETE && (
            <div className="bg-white border border-green-100 shadow-lg rounded-xl p-10 text-center animate-in zoom-in duration-300 relative overflow-hidden">
               <div className="absolute top-0 left-0 w-full h-1 bg-green-500"></div>
               <div className="w-20 h-20 bg-green-50 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                 <Check size={40} />
               </div>
               <h2 className="text-3xl font-bold text-slate-800 mb-3">All Tasks Completed!</h2>
               <p className="text-slate-500 mb-8 max-w-md mx-auto">Processed {totalCount} keywords successfully. All articles have been saved to the history log.</p>
               <div className="flex justify-center space-x-4">
                  <button 
                    onClick={() => setShowHistory(true)}
                    className="bg-white border-2 border-slate-100 text-slate-600 hover:border-orange-200 hover:text-orange-600 px-8 py-3 rounded-xl font-bold transition-all"
                  >
                    View History
                  </button>
                  <button 
                    onClick={() => {
                       setStatus(StepStatus.IDLE);
                       setBulkInput('');
                       setIdeationResult('');
                       setOutlineResult('');
                       setArticleResult('');
                       setCompletedCount(0);
                       setTotalCount(0);
                    }} 
                    className="text-white px-8 py-3 rounded-xl font-bold transition-all shadow-md hover:shadow-lg"
                    style={{ background: GOLD_GRADIENT }}
                  >
                    Start New Batch
                  </button>
               </div>
            </div>
          )}

          {(status === StepStatus.LOADING || status === StepStatus.COMPLETE) && (
            <>
              {ideationResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <ResultViewer 
                      title={`Step 2: Ideation (${currentKeyword})`} 
                      content={ideationResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {outlineResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-100">
                    <ResultViewer 
                      title={`Step 3: Outline (${currentKeyword})`} 
                      content={outlineResult} 
                      isCollapsible={true}
                      defaultOpen={false}
                    />
                </section>
              )}

              {articleResult && (
                <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 delay-200 space-y-6">
                    <ResultViewer 
                      title={`Step 4: Writing (${currentKeyword})`} 
                      content={articleResult} 
                      isCollapsible={true}
                      defaultOpen={true}
                      onRegenerateImage={handleRegenerateImage}
                    />

                    <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex items-center justify-between">
                       <div className="flex items-center space-x-3 text-slate-600">
                          <div className="p-3 bg-slate-100 text-slate-600 rounded-xl">
                             <Settings size={24} />
                          </div>
                          <div>
                            <p className="font-bold text-slate-800">Ready to Publish</p>
                            <p className="text-sm text-slate-500">Export your content below.</p>
                          </div>
                       </div>
                       <ExportActions />
                    </div>
                </section>
              )}
            </>
          )}

          <div ref={bottomRef} />

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { marked } from 'marked';
import JSZip from 'jszip';
import saveAs from 'file-saver';
import { AppStep, StepStatus, WpConfig, HistoryItem, OutputLanguage } from './types';
import { executeStep1, executeStep2, executeStep3, executeStep4, generateBlogImage, resetSession } from './services/geminiService';
import { getHistory, saveHistoryItem, deleteHistoryItem } from './services/storageService';
import { StepIndicator } from './components/StepIndicator';
import { ResultViewer } from './components/ResultViewer';
import { HistorySidebar } from './components/HistorySidebar';
import { Loader2, Send, Settings, ArrowRight, Check, History, List, X, Languages, Download, Copy, FileText, Package, Code, Sparkles, FileCode } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [status, setStatus] = useState<StepStatus>(StepStatus.IDLE);
  const [bulkInput, setBulkInput] = useState(''); // Textarea input
  const [language, setLanguage] = useState<OutputLanguage>('vi'); // Language selection

  const [queue, setQueue] = useState<string[]>([]); // Processing queue
  const [completedCount, setCompletedCount] = useState(0);
  const [totalCount, setTotalCount] = useState(0);
  const [currentKeyword, setCurrentKeyword] = useState(''); // Currently processing keyword

  const [statusMessage, setStatusMessage] = useState('');

  // Results
  const [ideationResult, setIdeationResult] = useState(''); 
  const [outlineResult, setOutlineResult] = useState(''); 
  const [articleResult, setArticleResult] = useState(''); 

  // History & Logs
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [viewingHistoryItem, setViewingHistoryItem] = useState<HistoryItem | null>(null);

  // Export State
  const [isZipping, setIsZipping] = useState(false);
  const [copyCleanSuccess, setCopyCleanSuccess] = useState(false);

  // Scroll ref
  const bottomRef = useRef<HTMLDivElement>(null);

  // Constants for Style
  const GOLD_GRADIENT = 'linear-gradient(135deg, rgb(255, 215, 0), rgb(255, 165, 0))';

  // Load History on Mount
  useEffect(() => {
    const loadData = async () => {
        const loadedHistory = await getHistory();
        setHistory(loadedHistory);
    };
    loadData();
  }, []);

  useEffect(() => {
    if (status !== StepStatus.IDLE && bottomRef.current) {
      setTimeout(() => {
          bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  }, [ideationResult, outlineResult, articleResult, status, statusMessage]);

  // --- Bulk Processing Logic ---

  const handleStartBulk = async () => {
    const keywords = bulkInput
      .split('\n')
      .map(k => k.trim())
      .filter(k => k.length > 0);

    if (keywords.length === 0) return;

    setQueue(keywords);
    setTotalCount(keywords.length);
    setCompletedCount(0);
    setStatus(StepStatus.LOADING);

    // Start processing the first keyword, capture current language
    processNextKeyword(keywords, language);
  };

  const processNextKeyword = async (remainingQueue: string[], selectedLang: OutputLanguage) => {
    if (remainingQueue.length === 0) {
      setStatus(StepStatus.COMPLETE);
      setStatusMessage("All keywords processed successfully!");
      setCurrentKeyword('');
      return;
    }

    const keyword = remainingQueue[0];
    const nextQueue = remainingQueue.slice(1);

    setCurrentKeyword(keyword);
    setQueue(nextQueue);
    setCompletedCount(prev => totalCount - remainingQueue.length);

    // Reset UI for new keyword
    setCurrentStep(AppStep.INPUT);
    setIdeationResult('');
    setOutlineResult('');
    setArticleResult('');
    resetSession();

    try {
      const langLabel = selectedLang === 'vi' ? 'VI' : 'EN';

      // --- Step 1 ---
      setStatusMessage(`[${keyword}][${langLabel}] Researching data (Step 1/4)...`);
      await executeStep1(keyword, selectedLang);

      // --- Step 2 ---
      setStatusMessage(`[${keyword}][${langLabel}] Generating Ideation (Step 2/4)...`);
      const ideation = await executeStep2(keyword, selectedLang);
      setIdeationResult(ideation);
      setCurrentStep(AppStep.IDEATION);

      // --- Step 3 ---
      setStatusMessage(`[${keyword}][${langLabel}] Creating Outline (Step 3/4)...`);
      const outline = await executeStep3(selectedLang);
      setOutlineResult(outline);
      setCurrentStep(AppStep.OUTLINE);

      // --- Step 4 ---
      setStatusMessage(`[${keyword}][${langLabel}] Writing Article (Step 4/4)...`);
      const rawArticle = await executeStep4(keyword, selectedLang);
      setArticleResult(rawArticle);
      setCurrentStep(AppStep.WRITING);

      // --- Images ---
      setStatusMessage(`[${keyword}] Generating Images (Vietnamese Context)...`);
      // Updated Regex to support [HÌNH ẢNH: ...] based on new prompt
      const imageRegex = /\[(?:IMAGE_PROMPT|HÌNH ẢNH):\s*(.*?)\]/gi;
      let finalArticle = rawArticle;
      const matches = [...rawArticle.matchAll(imageRegex)];

      if (matches.length > 0) {
        let processedCount = 0;
        for (const m of matches) {
            const placeholder = m[0];
            const prompt = m[1];
            setStatusMessage(`[${keyword}] Image ${processedCount + 1}/${matches.length}...`);
            const base64Image = await generateBlogImage(prompt);
            if (base64Image) {
                finalArticle = finalArticle.replace(placeholder, `\n\n![${prompt}](${base64Image})\n`);
            } else {
                finalArticle = finalArticle.replace(placeholder, ``);
            }
            setArticleResult(finalArticle);
            processedCount++;
        }
      }

      // --- Save to History ---
      const newItem: HistoryItem = {
        id: "", // Service will assign unique ID
        keyword: keyword,
        content: finalArticle,
        timestamp: Date.now(),
        language: selectedLang
      };

      console.log("Saving article to DB...");
      const updatedHistory = await saveHistoryItem(newItem);
      setHistory(updatedHistory);

      // --- Trigger Next ---
      setCompletedCount(prev => prev + 1);

      // Small delay between articles to avoid rate limits abruptly
      setStatusMessage(`[${keyword}] Finished! Starting next in 3s...`);
      await new Promise(r => setTimeout(r, 3000));

      processNextKeyword(nextQueue, selectedLang);

    } catch (error) {
      console.error(error);
      const errorItem: HistoryItem = {
        id: "",
        keyword: keyword + " (FAILED)",
        content: `Error processing: ${error}`,
        timestamp: Date.now(),
        language: selectedLang
      };
      const updatedHistory = await saveHistoryItem(errorItem);
      setHistory(updatedHistory);

      setStatusMessage(`Error with "${keyword}". Moving to next...`);
      await new Promise(r => setTimeout(r, 2000));
      processNextKeyword(nextQueue, selectedLang);
    }
  };

  // --- REGENERATE IMAGE LOGIC ---
  const handleRegenerateImage = async (oldSrc: string, altText: string) => {
      // Find the current content (either live or viewing history)
      const currentContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;

      // Generate new image
      const newBase64 = await generateBlogImage(altText);

      if (newBase64) {
          // Replace in content string
          const newContent = currentContent.replace(oldSrc, newBase64);

          if (viewingHistoryItem) {
              const updatedItem = { ...viewingHistoryItem, content: newContent };
              setViewingHistoryItem(updatedItem);
              const updatedHistory = await saveHistoryItem(updatedItem);
              setHistory(updatedHistory);
          } else {
              setArticleResult(newContent);
              const existingItem = history.find(h => h.keyword === currentKeyword);
              if (existingItem) {
                  const updatedItem = { ...existingItem, content: newContent };
                  const updatedHistory = await saveHistoryItem(updatedItem);
                  setHistory(updatedHistory);
              }
          }
      } else {
          alert("Could not regenerate image. Please try again.");
      }
  };

  // History Handlers
  const handleDeleteHistory = async (id: string) => {
    const updated = await deleteHistoryItem(id);
    setHistory(updated);
    if (viewingHistoryItem?.id === id) setViewingHistoryItem(null);
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setViewingHistoryItem(item);
    setShowHistory(false);
  };

  // --- EXPORT LOGIC ---

  const parseArticleData = (markdownContent: string, keyword: string) => {
    // Extract Meta Data
    const titleMatch = markdownContent.match(/Meta Title:\s*(.*)/);
    const descMatch = markdownContent.match(/Meta Description:\s*(.*)/);
    const slugMatch = markdownContent.match(/Slug:\s*(.*)/);

    const title = titleMatch ? titleMatch[1].trim() : keyword;
    const metaDesc = descMatch ? descMatch[1].trim() : '';
    const slug = slugMatch ? slugMatch[1].trim() : keyword.toLowerCase().replace(/[^a-z0-9]+/g, '-');

    // Clean Content
    const metaBlockRegex = /========== META DATA ==========\n([\s\S]*?)=============================/;
    let cleanBody = markdownContent.replace(metaBlockRegex, "").trim();
    cleanBody = cleanBody
        .replace(/========== NỘI DUNG BÀI VIẾT ==========/, "")
        .replace(/========== KẾT THÚC BÀI VIẾT ==========/, "")
        .trim();

    return { title, metaDesc, slug, cleanBody };
  };

  const handleCopyCleanHtml = async () => {
    const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
    const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
    const { cleanBody } = parseArticleData(rawContent, keyword);

    // Convert to HTML first using marked
    let html = await marked.parse(cleanBody);

    // Replace Base64 images with Placeholders using Regex on HTML
    let imgIndex = 1;
    html = html.replace(/<img[^>]*src=["']data:[^"']*["'][^>]*alt=["']([^"']*)["'][^>]*>/gi, (match, alt) => {
         const placeholder = `<div style="background-color: #f8fafc; border: 2px dashed #cbd5e1; padding: 20px; text-align: center; margin: 20px 0; border-radius: 8px;">
            <p style="font-weight: bold; color: #1e40af; margin-bottom: 5px;">[CHÈN ẢNH ${imgIndex}: image-${imgIndex}.png]</p>
            <p style="color: #64748b; font-size: 0.9em; font-style: italic;">Alt Text: ${alt}</p>
         </div>`;
         imgIndex++;
         return placeholder;
    });

    try {
        await navigator.clipboard.writeText(html);
        setCopyCleanSuccess(true);
        setTimeout(() => setCopyCleanSuccess(false), 3000);
    } catch (err) {
        console.error('Failed to copy', err);
        alert('Failed to copy code.');
    }
  };

  const handleDownloadWxrXml = async () => {
    try {
        const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
        const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
        const { title, metaDesc, slug, cleanBody } = parseArticleData(rawContent, keyword);
        const htmlContent = await marked.parse(cleanBody);

        const xmlContent = `<?xml version="1.0" encoding="UTF-8" ?>
<rss version="2.0"
	xmlns:excerpt="http://wordpress.org/export/1.2/excerpt/"
	xmlns:content="http://purl.org/rss/1.0/modules/content/"
	xmlns:wfw="http://wellformedweb.org/CommentAPI/"
	xmlns:dc="http://purl.org/dc/elements/1.1/"
	xmlns:wp="http://wordpress.org/export/1.2/"
>
<channel>
	<title>BestMarathon Export</title>
	<pubDate>${new Date().toUTCString()}</pubDate>
	<language>vi</language>
	<wp:wxr_version>1.2</wp:wxr_version>
	<item>
		<title><![CDATA[${title}]]></title>
		<link></link>
		<pubDate>${new Date().toUTCString()}</pubDate>
		<dc:creator><![CDATA[admin]]></dc:creator>
		<guid isPermaLink="false"></guid>
		<description></description>
		<content:encoded><![CDATA[${htmlContent}]]></content:encoded>
		<excerpt:encoded><![CDATA[]]></excerpt:encoded>
		<wp:post_id>${Math.floor(Math.random() * 100000)}</wp:post_id>
		<wp:post_date>${new Date().toISOString().replace('T', ' ').split('.')[0]}</wp:post_date>
		<wp:comment_status>open</wp:comment_status>
		<wp:ping_status>open</wp:ping_status>
		<wp:post_name><![CDATA[${slug}]]></wp:post_name>
		<wp:status>draft</wp:status>
		<wp:post_parent>0</wp:post_parent>
		<wp:menu_order>0</wp:menu_order>
		<wp:post_type>post</wp:post_type>
		<wp:post_password></wp:post_password>
		<wp:is_sticky>0</wp:is_sticky>
        <!-- YOAST SEO METADATA -->
        <wp:postmeta>
            <wp:meta_key>_yoast_wpseo_title</wp:meta_key>
            <wp:meta_value><![CDATA[${title}]]></wp:meta_value>
        </wp:postmeta>
        <wp:postmeta>
            <wp:meta_key>_yoast_wpseo_metadesc</wp:meta_key>
            <wp:meta_value><![CDATA[${metaDesc}]]></wp:meta_value>
        </wp:postmeta>
        <!-- RANK MATH METADATA -->
        <wp:postmeta>
            <wp:meta_key>rank_math_title</wp:meta_key>
            <wp:meta_value><![CDATA[${title}]]></wp:meta_value>
        </wp:postmeta>
        <wp:postmeta>
            <wp:meta_key>rank_math_description</wp:meta_key>
            <wp:meta_value><![CDATA[${metaDesc}]]></wp:meta_value>
        </wp:postmeta>
        <!-- ALL IN ONE SEO METADATA -->
        <wp:postmeta>
            <wp:meta_key>_aioseop_title</wp:meta_key>
            <wp:meta_value><![CDATA[${title}]]></wp:meta_value>
        </wp:postmeta>
        <wp:postmeta>
            <wp:meta_key>_aioseop_description</wp:meta_key>
            <wp:meta_value><![CDATA[${metaDesc}]]></wp:meta_value>
        </wp:postmeta>
	</item>
</channel>
</rss>`;

        const blob = new Blob([xmlContent], { type: "text/xml;charset=utf-8" });
        saveAs(blob, `${slug || 'article'}.xml`);

    } catch (e) {
        console.error("XML Export Error", e);
        alert("Failed to create XML file");
    }
  };

  const handleDownloadPackage = async () => {
    setIsZipping(true);
    try {
        const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
        const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
        const { cleanBody, slug } = parseArticleData(rawContent, keyword);
        const safeKeyword = slug || keyword.replace(/[^a-zA-Z0-9\s-_]/g, '').trim().replace(/\s+/g, '-');

        const zip = new JSZip();

        // 1. Extract Images and Clean Markdown
        const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
        let cleanMD = cleanBody;

        let imgIndex = 1;
        const matches = [...cleanBody.matchAll(imageRegex)];

        // Create images folder
        const imgFolder = zip.folder("images");

        // Loop through images to process
        for (const match of matches) {
            const originalTag = match[0];
            const altText = match[1] || `image-${imgIndex}`;
            const base64Full = match[2];

            // Extract pure base64
            const base64Data = base64Full.split(',')[1];
            const mimeType = base64Full.split(';')[0].split(':')[1];
            const ext = mimeType === 'image/jpeg' ? 'jpg' : 'png';

            // STRICT NAMING: image-1.png, image-2.png
            const fileName = `image-${imgIndex}.${ext}`;

            // Add to zip
            imgFolder?.file(fileName, base64Data, {base64: true});

            // Replace text in MD for clarity
            cleanMD = cleanMD.replace(originalTag, `\n> [CHÈN ẢNH ${imgIndex}: images/${fileName}]\n> Alt: ${altText}\n`);

            imgIndex++;
        }

        // 2. Add Text Content
        zip.file(`${safeKeyword}-content.txt`, cleanMD);

        // 3. Add Word Doc
        const docHtml = `
          <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
          <head><meta charset="utf-8"></head>
          <body>${await marked.parse(cleanBody)}</body>
          </html>`;
        zip.file(`${safeKeyword}-visual-editor.doc`, docHtml);

        // 4. Generate
        const content = await zip.generateAsync({type: "blob"});
        saveAs(content, `BestMarathon-${safeKeyword}.zip`);

    } catch (e) {
        console.error("Zip Error", e);
        alert("Failed to create zip package");
    } finally {
        setIsZipping(false);
    }
  };

  const renderLoading = () => (
    <div className="flex flex-col items-center justify-center p-8 text-slate-500 animate-pulse bg-white rounded-xl border border-blue-100 shadow-sm mb-8">
      <Loader2 className="w-10 h-10 animate-spin mb-4 text-orange-500" />
      <p className="text-lg font-medium text-slate-800">{statusMessage}</p>
      <div className="w-full max-w-md bg-slate-100 rounded-full h-2.5 mt-4 overflow-hidden">
        <div 
          className="h-2.5 rounded-full transition-all duration-500" 
          style={{ 
            width: `${totalCount > 0 ? (completedCount / totalCount) * 100 : 0}%`,
            background: GOLD_GRADIENT 
          }}
        ></div>
      </div>
      <p className="text-xs mt-2 text-slate-500">Processed {completedCount} of {totalCount} keywords</p>
    </div>
  );

  // New "Manual Export" Component
  const ExportActions = () => (
      <div className="flex flex-col space-y-3 items-end">

         <div className="text-sm text-slate-500 mb-2 font-medium">Export Options:</div>

         <div className="flex flex-wrap gap-3 justify-end">
             {/* Option 3: XML Import (NEW) */}
             <button 
                onClick={handleDownloadWxrXml}
                className="flex items-center space-x-2 bg-orange-50 hover:bg-orange-100 text-orange-800 border border-orange-200 px-4 py-3 rounded-lg font-bold shadow-sm transition-all active:scale-95"
                title="Download .xml file to import directly into WordPress (Tools > Import)"
             >
                <FileCode size={20} />
                <span>WP Import (.xml)</span>
             </button>

             {/* Option 2: Full Package */}
             <button 
                onClick={handleDownloadPackage}
                disabled={isZipping}
                className="flex items-center space-x-2 text-white px-5 py-3 rounded-lg font-bold shadow-md transition-all active:scale-95 disabled:opacity-70 disabled:grayscale"
                style={{ background: GOLD_GRADIENT }}
                title="Download ZIP with separate named images (image-1.png, etc)"
             >
                {isZipping ? <Loader2 size={20} className="animate-spin" /> : <Package size={20} />}
                <span>Download All (.zip)</span>
             </button>

             {/* Option 1: Clean HTML */}
             <button 
                onClick={handleCopyCleanHtml}
                className="flex items-center space-x-2 bg-slate-50 hover:bg-slate-100 text-slate-700 border border-slate-200 px-4 py-3 rounded-lg font-bold shadow-sm transition-all active:scale-95"
                title="Copy HTML code without huge base64 strings."
             >
                {copyCleanSuccess ? <Check size={20} className="text-green-600"/> : <Code size={20} />}
             </button>
         </div>

         {copyCleanSuccess && (
             <div className="text-green-600 text-sm font-semibold animate-in fade-in slide-in-from-top-1">
                 Copied Clean HTML!
             </div>
         )}

         <div className="text-xs text-slate-500 bg-white p-3 rounded-lg border border-slate-200 shadow-sm max-w-sm text-right">
             <p className="mb-1 text-orange-600 font-semibold">🔥 Recommended: Use "WP Import (.xml)"</p>
             <p>Go to <b>Tools {'>'} Import {'>'} WordPress</b> to upload this file. Title, Slug, & SEO Meta will be set automatically.</p>
         </div>
      </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">

      <HistorySidebar 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
        history={history}
        onSelect={handleSelectHistory}
        onDelete={handleDeleteHistory}
      />

      {viewingHistoryItem && (
        <div className="fixed inset-0 z-50 bg-slate-100 overflow-y-auto">
          <div className="max-w-5xl mx-auto px-4 py-8">
