</channel>
</rss>`;

        const blob = new Blob([xmlContent], { type: "text/xml;charset=utf-8" });
        saveAs(blob, `${slug || 'article'}.xml`);

    } catch (e) {
        console.error("XML Export Error", e);
        alert("Failed to create XML file");
    } finally {
        setIsZipping(false);
    }
  };

  const handleDownloadPackage = async () => {
    setIsZipping(true);
    try {
        const rawContent = viewingHistoryItem ? viewingHistoryItem.content : articleResult;
        const keyword = viewingHistoryItem ? viewingHistoryItem.keyword : currentKeyword;
        const { cleanBody, slug } = parseArticleData(rawContent, keyword);
        const safeKeyword = slug || keyword.replace(/[^a-zA-Z0-9\s-_]/g, '').trim().replace(/\s+/g, '-');

        const zip = new JSZip();

        // 1. Extract Images and Clean Markdown
        const imageRegex = /!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g;
        let cleanMD = cleanBody;

        let imgIndex = 1;
        const matches = [...cleanBody.matchAll(imageRegex)];

        // Create images folder
        const imgFolder = zip.folder("images");

        // Loop through images to process
        for (const match of matches) {
            const originalTag = match[0];
            const altText = match[1] || `image-${imgIndex}`;
            const base64Full = match[2];

            // Extract pure base64
            const base64Data = base64Full.split(',')[1];
            const mimeType = base64Full.split(';')[0].split(':')[1];
            const ext = mimeType === 'image/jpeg' ? 'jpg' : 'png';

            // STRICT NAMING: image-1.png, image-2.png, or featured.jpg
            let fileName = '';
            if (altText === 'FEATURED_IMAGE') {
                fileName = `featured-image.${ext}`;
            } else {
                fileName = `image-${imgIndex}.${ext}`;
                imgIndex++;
            }

            // Add to zip
            imgFolder?.file(fileName, base64Data, {base64: true});

            // Replace text in MD for clarity
            cleanMD = cleanMD.replace(originalTag, `\n> [CHÈN ẢNH ${altText === 'FEATURED_IMAGE' ? 'THUMBNAIL' : imgIndex}: images/${fileName}]\n> Alt: ${altText}\n`);
        }

        // 2. Add Text Content
        zip.file(`${safeKeyword}-content.txt`, cleanMD);

        // 3. Add Word Doc
        const docHtml = `
          <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
          <head><meta charset="utf-8"></head>
          <body>${await marked.parse(cleanBody)}</body>
          </html>`;
        zip.file(`${safeKeyword}-visual-editor.doc`, docHtml);

        // 4. Generate
        const content = await zip.generateAsync({type: "blob"});
        saveAs(content, `BestMarathon-${safeKeyword}.zip`);

    } catch (e) {
        console.error("Zip Error", e);
        alert("Failed to create zip package");
    } finally {
        setIsZipping(false);
    }
