<!-- wp:image {"id":${attachmentId}} -->
<figure class="wp-block-image"><img src="${compressedBase64}" alt="${altText}" class="wp-image-${attachmentId}"/><figcaption>${altText}</figcaption></figure>
<!-- /wp:image -->`;
